175	async function resolveInterviewRoute(db: ReturnType<typeof getDirectDb>): Promise<OracleModelRoute> {
176	  const resolved = await resolveRouteFromSettings(db, 'interview');
177	  if (resolved) return resolved;
178	  const fallback = getOracleRoute(FALLBACK_INTERVIEW_ROUTE_ID);
179	  if (!fallback) throw new Error(`Fallback interview route ${FALLBACK_INTERVIEW_ROUTE_ID} missing`);
180	  return fallback;
181	}
