183	async function findOrCreateLiveChannel(db: ReturnType<typeof getDirectDb>, botId: string): Promise<string> {
184	  const existing = await db
185	    .select({ id: channels.id })
186	    .from(channels)
187	    .where(sql`${channels.name} = ${`Teams live meeting ${botId}`}`)
188	    .limit(1);
189	  if (existing[0]) return existing[0].id;
190	
191	  const [channel] = await db
192	    .insert(channels)
193	    .values({
194	      name: `Teams live meeting ${botId}`,
195	      isGroupChat: true,
196	      status: 'active',
197	    })
198	    .returning({ id: channels.id });
199	  if (!channel) throw new Error('failed to create live Teams channel');
200	  return channel.id;
201	}
