203	async function resolveEmployeeId(
204	  db: ReturnType<typeof getDirectDb>,
205	  speaker: { name: string | null; email: string | null },
206	): Promise<string | null> {
207	  if (speaker.email) {
208	    const byEmail = await db
209	      .select({ id: employees.id })
210	      .from(employees)
211	      .where(sql`lower(${employees.email}) = ${speaker.email.toLowerCase()}`)
212	      .limit(1);
213	    if (byEmail[0]) return byEmail[0].id;
214	  }
215	  if (speaker.name) {
216	    const byName = await db
217	      .select({ id: employees.id })
218	      .from(employees)
219	      .where(sql`lower(${employees.name}) = ${speaker.name.trim().toLowerCase()}`)
220	      .limit(1);
221	    if (byName[0]) return byName[0].id;
222	  }
223	  return null;
224	}
