265	async function channelRateState(db: ReturnType<typeof getDirectDb>, channelId: string): Promise<{
266	  minutesSinceLast: number | null;
267	  inLastHour: number;
268	}> {
269	  const last = await db
270	    .select({ createdAt: oracleInterventions.createdAt })
271	    .from(oracleInterventions)
272	    .where(eq(oracleInterventions.channelId, channelId))
273	    .orderBy(desc(oracleInterventions.createdAt))
274	    .limit(1);
275	  const minutesSinceLast = last[0]
276	    ? Math.floor((Date.now() - last[0].createdAt.getTime()) / 60_000)
277	    : null;
278	  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
279	  const countRows = await db
280	    .select({ c: sql<number>`count(*)::int` })
281	    .from(oracleInterventions)
282	    .where(and(eq(oracleInterventions.channelId, channelId), gte(oracleInterventions.createdAt, oneHourAgo)));
283	  return { minutesSinceLast, inLastHour: countRows[0]?.c ?? 0 };
284	}
