286	function isWorthModelPass(text: string): boolean {
287	  if (text.length < 40) return false;
288	  return /\b(always|never|usually|not always|exception|approval|approved|send|handoff|handover|Coldlion|ERP|China|factory|routing|Burlington|TJX|Ross|Walmart|Disney|Marvel|licensor|customer|sample|production|shipping|cost|workaround|spreadsheet|process)\b/i.test(text);
289	}
290	
291	function forcedTestQuestion(text: string): string {
292	  const cleaned = stripOracleAddress(text).replace(/^test[:,]?\s*/i, '').replace(/\s+/g, ' ').trim();
293	  if (!cleaned) return 'Quick Oracle test: what should we clarify from the current discussion?';
294	  return cleaned.endsWith('?') ? cleaned : `${cleaned}?`;
295	}
296	
297	function stripOracleAddress(text: string): string {
298	  return text
299	    .replace(/^\s*(hey\s+)?oracle[:,]?\s*/i, '')
300	    .replace(/\s+/g, ' ')
301	    .trim();
302	}
303	
304	function isMetaOracleQuestion(text: string): boolean {
305	  return /\b(oracle|ai|transcription|transcript|record|recording|listen|listening|eavesdropping|bot)\b/i.test(text);
306	}
307	
308	function isDirectBusinessQuestion(text: string): boolean {
309	  const content = stripOracleAddress(text);
310	  if (!content.includes('?')) return false;
311	  if (isMetaOracleQuestion(content)) return false;
312	  return isWorthModelPass(content);
313	}
314	
315	function fallbackClarificationQuestion(text: string): string {
316	  const content = stripOracleAddress(text).replace(/\s+/g, ' ').trim();
317	  if (!content) return 'Can we clarify the business-process question that was just raised?';
318	  return `Can we clarify this process question: ${content}`;
319	}
320	
321	function truncateForPrompt(text: string, maxChars: number): string {
322	  const normalized = text.replace(/\s+/g, ' ').trim();
323	  if (normalized.length <= maxChars) return normalized;
324	  return `${normalized.slice(0, Math.max(0, maxChars - 3)).trimEnd()}...`;
325	}
326	
327	async function loadEvidenceForClaims(
328	  db: ReturnType<typeof getDirectDb>,
329	  claimIds: string[],
330	): Promise<Map<string, {
331	  evidenceId: string;
332	  exactQuote: string;
333	  sourceMessageId: string | null;
334	  sourceDocumentChunkId: string | null;
335	  sourceExternalRecordId: string | null;
336	}>> {
337	  if (claimIds.length === 0) return new Map();
338	
339	  const rows = await db
340	    .select({
341	      evidenceId: claimEvidence.id,
342	      claimId: claimEvidence.claimId,
343	      exactQuote: claimEvidence.exactQuote,
344	      sourceMessageId: claimEvidence.sourceMessageId,
345	      sourceDocumentChunkId: claimEvidence.sourceDocumentChunkId,
346	      sourceExternalRecordId: claimEvidence.sourceExternalRecordId,
347	      createdAt: claimEvidence.createdAt,
348	    })
349	    .from(claimEvidence)
350	    .where(inArray(claimEvidence.claimId, claimIds))
351	    .orderBy(desc(claimEvidence.createdAt));
352	
353	  const byClaim = new Map<string, {
354	    evidenceId: string;
355	    exactQuote: string;
356	    sourceMessageId: string | null;
357	    sourceDocumentChunkId: string | null;
358	    sourceExternalRecordId: string | null;
359	  }>();
360	  for (const row of rows) {
361	    if (byClaim.has(row.claimId)) continue;
362	    byClaim.set(row.claimId, {
363	      evidenceId: row.evidenceId,
364	      exactQuote: row.exactQuote,
365	      sourceMessageId: row.sourceMessageId,
366	      sourceDocumentChunkId: row.sourceDocumentChunkId,
367	      sourceExternalRecordId: row.sourceExternalRecordId,
368	    });
369	  }
370	  return byClaim;
371	}
