373	async function buildLiveRetrievalContext(args: {
374	  db: ReturnType<typeof getDirectDb>;
375	  currentUtterance: string;
376	  recentContext: string;
377	}): Promise<LiveRetrievalContext | null> {
378	  const retrievalQuery = [
379	    stripOracleAddress(args.currentUtterance),
380	    args.recentContext ? `Recent meeting context:\n${args.recentContext}` : '',
381	  ].filter(Boolean).join('\n\n');
382	  if (!retrievalQuery) return null;
383	
384	  try {
385	    const plan = buildRetrievalPlanFromQuery(retrievalQuery, { topK: LIVE_RETRIEVAL_TOP_K });
386	    const claims = await searchWithRetrievalPlan(args.db, plan);
387	    const evidenceByClaim = await loadEvidenceForClaims(args.db, claims.map((c) => c.id));
388	    const sectionRows = claims.length > 0
389	      ? await args.db
390	          .select({ sectionId: sectionClaims.sectionId })
391	          .from(sectionClaims)
392	          .where(inArray(sectionClaims.claimId, claims.map((c) => c.id)))
393	          .limit(2)
394	      : [];
395	    const sectionIds = Array.from(new Set(sectionRows.map((r) => r.sectionId))).slice(0, 2);
396	    const brainSnippets = await getBrainSectionSnippets(args.db, sectionIds);
397	
398	    const enrichedClaims: LiveRetrievedClaimContext[] = claims.map((claim) => {
399	      const evidence = evidenceByClaim.get(claim.id);
400	      return {
401	        ...claim,
402	        evidenceId: evidence?.evidenceId ?? null,
403	        evidenceQuote: evidence?.exactQuote ?? null,
404	        sourceMessageId: evidence?.sourceMessageId ?? null,
405	        sourceDocumentChunkId: evidence?.sourceDocumentChunkId ?? null,
406	        sourceExternalRecordId: evidence?.sourceExternalRecordId ?? null,
407	      };
408	    });
409	
410	    const claimsText = enrichedClaims.length > 0
411	      ? enrichedClaims.map((claim, i) => {
412	          const quote = claim.evidenceQuote
413	            ? ` Evidence: "${truncateForPrompt(claim.evidenceQuote, 220)}"`
414	            : '';
415	          return `[C${i + 1}] ${truncateForPrompt(claim.summary, 260)} (impact ${claim.impactScore}, confidence ${claim.confidenceScore}).${quote}`;
416	        }).join('\n')
417	      : 'No approved claims matched this live context.';
418	    const brainText = brainSnippets.length > 0
419	      ? brainSnippets.map((section, i) =>
420	          `[B${i + 1}] ${section.title}: ${truncateForPrompt(section.markdown, 420)}`,
421	        ).join('\n')
422	      : 'No linked Brain sections found for retrieved claims.';
423	    const contextText = `Approved claims:\n${claimsText}\n\nLinked Brain sections:\n${brainText}`;
424	
425	    return {
426	      plan,
427	      claims: enrichedClaims,
428	      brainSections: brainSnippets,
429	      contextText,
430	      includedClaimIds: enrichedClaims.map((c) => c.id),
431	      includedEvidenceIds: enrichedClaims.flatMap((c) => c.evidenceId ? [c.evidenceId] : []),
432	      includedBrainSectionIds: brainSnippets.map((s) => s.sectionId),
433	    };
434	  } catch (err) {
435	    const cause = err instanceof Error && err.cause instanceof Error ? ` cause: ${err.cause.message}` : '';
436	    console.warn(
437	      '[teams-live-recall-utterance] retrieval failed; deciding without approved-knowledge context',
438	      `${err instanceof Error ? err.message.slice(0, 300) : String(err)}${cause}`,
439	    );
440	    return null;
441	  }
442	}
443	
444	async function decideLiveQuestion(args: {
445	  db: ReturnType<typeof getDirectDb>;
446	  client: OracleAIClient;
447	  route: OracleModelRoute;
448	  channelId: string;
449	  currentUtterance: string;
450	  speakerName: string | null;
451	}): Promise<{
452	  decision: LiveQuestionDecision;
453	  modelRunId: string | null;
454	  retrievalContext: LiveRetrievalContext | null;
455	}> {
456	  const recent = await args.db
457	    .select({ id: messages.id, content: messages.content, metadataJson: messages.metadataJson, createdAt: messages.createdAt })
458	    .from(messages)
459	    .where(and(eq(messages.channelId, args.channelId), eq(messages.role, 'user'), isNull(messages.deletedAt)))
460	    .orderBy(desc(messages.createdAt))
461	    .limit(RECENT_UTTERANCE_LIMIT);
462	
463	  const recentContext = recent
464	    .slice()
465	    .reverse()
466	    .map((m, i) => {
467	      const meta = (m.metadataJson ?? {}) as { speaker?: string };
468	      return `[${i + 1}] ${meta.speaker ? `${meta.speaker}: ` : ''}${m.content}`;
469	    })
470	    .join('\n');
471	  const retrievalContext = await buildLiveRetrievalContext({
472	    db: args.db,
473	    currentUtterance: args.currentUtterance,
474	    recentContext,
475	  });
476	  const retrievalContextText = retrievalContext?.contextText ?? 'Approved-knowledge retrieval was unavailable for this utterance.';
477	  const userContent = `Recent finalized meeting utterances (oldest first):
478	${recentContext}
479	
480	Retrieved approved Oracle knowledge:
481	${retrievalContextText}
482	
483	Current utterance to evaluate:
484	${args.speakerName ? `${args.speakerName}: ` : ''}${args.currentUtterance}`;
485	
486	  const blocks = [
487	    makeBlock({
488	      id: 'sys',
489	      label: 'Teams live Oracle decision system',
490	      kind: 'stable_system',
491	      content: LIVE_ORACLE_SYSTEM,
492	      cacheEligible: true,
493	      reasonIncluded: 'live Teams meeting interjection decision',
494	    }),
495	    ...(retrievalContext
496	      ? [
497	          makeBlock({
498	            id: 'retrieved-claims',
499	            label: 'Retrieved approved Oracle knowledge',
500	            kind: 'retrieved_context' as const,
501	            content: retrievalContext.contextText,
502	            cacheEligible: false,
503	            reasonIncluded: 'approved claims and Brain sections retrieved for live Teams decision',
504	          }),
505	        ]
506	      : []),
507	    makeBlock({
508	      id: 'utterances',
509	      label: 'Recent finalized utterances',
510	      kind: 'dynamic_input',
511	      content: userContent,
512	      cacheEligible: false,
513	      reasonIncluded: 'rolling live Teams transcript window',
514	    }),
515	  ];
516	
517	  const [contextPack] = await args.db
518	    .insert(oracleContextPacks)
519	    .values({
520	      taskType: 'interview_chat',
521	      routeId: args.route.routeId,
522	      promptVersion: LIVE_PROMPT_VERSION,
523	      stablePrefixHash: hashString(LIVE_ORACLE_SYSTEM),
524	      retrievedContextHash: retrievalContext ? hashString(retrievalContext.contextText) : null,
525	      dynamicInputHash: hashString(userContent),
526	      blocksJson: blocks.map((b) => ({
527	        id: b.id,
528	        kind: b.kind,
529	        hash: b.hash,
530	        tokenEstimate: b.tokenEstimate,
531	      })),
532	      selectedDomains: retrievalContext
533	        ? retrievalContext.plan.searchScope === 'domain_filtered'
534	          ? retrievalContext.plan.topDomainHints
535	          : [retrievalContext.plan.searchScope === 'global_explicit' ? '_global_explicit' : '_global_fallback']
536	        : [],
537	      selectedSourceTypes: retrievalContext?.includedBrainSectionIds.length
538	        ? ['approved_claim', 'brain_section', 'message']
539	        : retrievalContext ? ['approved_claim', 'message'] : ['message'],
540	      selectedProcessStages: retrievalContext?.plan.processStageHints ?? [],
541	      selectedEntityIds: retrievalContext?.plan.requiredEntities.map((e) => `${e.entityType}:${e.canonicalValue}`) ?? [],
542	      includedMessageIds: recent.map((m) => m.id),
543	      includedClaimIds: retrievalContext?.includedClaimIds ?? [],
544	    })
545	    .returning({ id: oracleContextPacks.id });
546	  if (!contextPack) throw new Error('failed to insert oracle_context_packs row');
547	
548	  const callStartedAt = Date.now();
549	  let modelRunId: string | null = null;
550	  try {
551	    const result = await args.client.runObject<LiveQuestionDecision>({
552	      taskType: 'interview_chat',
553	      routeId: args.route.routeId,
554	      promptVersion: LIVE_PROMPT_VERSION,
555	      blocks,
556	      schema: LiveQuestionDecisionSchema,
557	    });
558	    const latencyMs = Date.now() - callStartedAt;
559	    const actualRouteId = result.routeId ?? args.route.routeId;
560	    const actualProvider = result.provider ?? args.route.provider;
