250	// Trigger.dev scheduled wrapper — production cron entry point. Delegates
251	// every line of behavior to runClaimExtractionOnce so the two paths
252	// can never drift.
253	export const claimExtractionTask = schedules.task({
254	  id: 'claim-extraction',
255	  cron: '0 */4 * * *',
256	  maxDuration: 60 * 5,
257	  run: async (_payload, { ctx }) => {
258	    return runClaimExtractionOnce(ctx.run.id);
259	  },
