265	
266	interface SegmentOutcome {
267	  candidatesStaged: number;
268	  claimsPromoted: number;
269	  duplicatesAppended: number;
270	  rejections: number;
271	  circuitBreakerTripped: boolean;
272	  messagesProcessed: number;
273	}
274	
275	interface ProcessSegmentArgs {
276	  db: OracleDb;
277	  client: OracleAIClient;
278	  route: OracleModelRoute;
279	  activeTopDomainIds: string[];
280	  entityRegistry: RegistryEntity[];
281	  jobRunId: string;
282	  segment: FormattedMessage[];
283	}
284	
285	async function processSegment(args: ProcessSegmentArgs): Promise<SegmentOutcome> {
286	  const { db, client, route, activeTopDomainIds, entityRegistry, jobRunId, segment } = args;
287	  const segmentIds = segment.map((m) => m.id);
288	  const userMessages = segment.filter((m) => m.role === 'user');
289	
290	  const outcome: SegmentOutcome = {
291	    candidatesStaged: 0,
292	    claimsPromoted: 0,
293	    duplicatesAppended: 0,
294	    rejections: 0,
295	    circuitBreakerTripped: false,
296	    messagesProcessed: 0,
297	  };
298	
299	  if (userMessages.length === 0) {
300	    await db
301	      .update(messages)
302	      .set({ extractionStatus: 'skipped', extractedAt: new Date() })
303	      .where(inArray(messages.id, segmentIds));
304	    outcome.messagesProcessed = segmentIds.length;
305	    return outcome;
306	  }
307	
308	  // Compile the prompt plan.
309	  const formatted = formatConversationSegment(segment);
310	  const blocks = [
311	    makeBlock({
312	      id: 'extraction-system',
313	      label: 'Extraction system prompt',
314	      kind: 'stable_system',
315	      content: EXTRACTION_SYSTEM_PROMPT,
316	      reasonIncluded: 'extraction prompt v' + EXTRACTION_PROMPT_VERSION,
317	    }),
318	    makeBlock({
319	      id: 'segment',
320	      label: 'Conversation segment to extract from',
321	      kind: 'dynamic_input',
322	      content: formatted,
323	      reasonIncluded: `segment of ${segment.length} message(s) in this batch`,
324	    }),
325	  ];
326	  const plan = client.compile({
327	    taskType: 'message_claim_extraction',
328	    routeId: route.routeId,
329	    promptVersion: EXTRACTION_PROMPT_VERSION,
330	    blocks,
331	    observability: { includedMessageIds: segmentIds },
332	  });
333	  const sourceHash = createHash('sha256').update(formatted, 'utf8').digest('hex');
334	
335	  // 1. Stage an extraction_batches row.
336	  const [batch] = await db
337	    .insert(extractionBatches)
338	    .values({
339	      jobRunId,
340	      batchType: 'message_segment',
341	      status: 'pending_model',
342	      sourceMessageIds: segmentIds,
343	      sourceHash,
344	      modelRunIdsAttempted: [],
345	      routeIdsAttempted: [route.routeId],
346	    })
347	    .returning({ id: extractionBatches.id });
348	  if (!batch) throw new Error('[claim-extraction] failed to insert extraction_batches row');
349	
350	  // 2. Stage the context pack BEFORE the model call so its ID can thread
351	  //    through. model_run_id stays null until the model_run is logged.
352	  const [contextPack] = await db
353	    .insert(oracleContextPacks)
354	    .values(buildContextPackInsert(plan))
355	    .returning({ id: oracleContextPacks.id });
356	  if (!contextPack) throw new Error('[claim-extraction] failed to insert oracle_context_packs row');
357	
358	  await db
359	    .update(extractionBatches)
360	    .set({ contextPackId: contextPack.id })
361	    .where(eq(extractionBatches.id, batch.id));
362	
363	  // 3. Call the model.
364	  const callStartedAt = Date.now();
365	  let modelOutput: ExtractionOutput | null = null;
366	  let modelRunId: string | null = null;
367	  let modelError: unknown = null;
368	
369	  try {
370	    const result = await client.runObject<ExtractionOutput>({
371	      taskType: 'message_claim_extraction',
372	      routeId: route.routeId,
373	      promptVersion: EXTRACTION_PROMPT_VERSION,
374	      blocks,
375	      schema: ExtractionOutputSchema,
376	      observability: { includedMessageIds: segmentIds },
377	      providerOptions: {
378	        cache: {
379	          preferExplicitCache: route.provider === 'vertex',
380	          cacheTtlSeconds: 15 * 60,
381	          expectedReuseCount: 2,
382	          persistProviderCacheRecord: route.provider === 'vertex',
383	          sourceDescription: `message segment ${segmentIds[0]}..${segmentIds[segmentIds.length - 1]}`,
384	          cleanupOwner: 'claim-extraction-worker',
385	          createdByJobRunId: jobRunId,
386	          latestPlannedReuseStep: 'message_claim_extraction',
387	        },
388	      },
389	    });
390	    const latencyMs = Date.now() - callStartedAt;
391	    const actualRouteId = result.routeId ?? route.routeId;
392	    const actualProvider = result.provider ?? route.provider;
393	    const actualModelId = result.modelId ?? route.modelId;
394	
395	    // Log model_runs row.
396	    const [modelRun] = await db
397	      .insert(modelRuns)
398	      .values({
399	        taskType: 'claim-extraction',
400	        model: actualModelId,
401	        provider: actualProvider,
402	        promptVersion: EXTRACTION_PROMPT_VERSION,
403	        inputHash: plan.metadata.stablePrefixHash,
404	        inputTokens: result.usage.inputTokens ?? null,
405	        outputTokens: result.usage.outputTokens ?? null,
406	        latencyMs,
407	        success: result.validation.ok,
408	      })
409	      .returning({ id: modelRuns.id });
410	    if (!modelRun) throw new Error('[claim-extraction] failed to insert model_runs row');
411	    modelRunId = modelRun.id;
412	
413	    // Log model_run_usage_details + back-link context pack.
414	    await db.insert(modelRunUsageDetails).values({
415	      modelRunId: modelRun.id,
416	      contextPackId: contextPack.id,
417	      routeId: actualRouteId,
418	      inputTokens: result.usage.inputTokens ?? null,
419	      cachedInputTokens: result.usage.cachedInputTokens ?? null,
420	      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
421	      outputTokens: result.usage.outputTokens ?? null,
422	      reasoningTokens: result.usage.reasoningTokens ?? null,
423	      providerRequestId: result.usage.providerRequestId ?? null,
424	      rawUsageJson: result.usage.rawUsageJson ?? null,
425	      fellBackFromRouteId: result.fellBackFromRouteId ?? null,
426	      fallbackReason: result.fallbackReason ?? null,
427	    });
428	    await db
429	      .update(oracleContextPacks)
430	      .set({ modelRunId: modelRun.id })
431	      .where(eq(oracleContextPacks.id, contextPack.id));
432	    await db
433	      .update(extractionBatches)
434	      .set({
435	        modelRunId: modelRun.id,
436	        modelRunIdsAttempted: [modelRun.id],
437	        rawModelOutput: result.object as unknown as Record<string, unknown>,
438	        status: result.validation.ok ? 'model_complete' : 'failed',
439	      })
440	      .where(eq(extractionBatches.id, batch.id));
441	
442	    if (!result.validation.ok) {
443	      throw new Error(
444	        '[claim-extraction] model output failed Zod schema validation: ' +
445	          result.validation.error.message,
446	      );
447	    }
448	    modelOutput = result.object;
449	  } catch (err) {
450	    modelError = err;
451	    if (!modelRunId) {
452	      // The model_runs row was never inserted. Insert a failed one now so
453	      // the batch has provenance.
454	      await db.insert(modelRuns).values({
455	        taskType: 'claim-extraction',
456	        model: route.modelId,
457	        provider: route.provider,
458	        promptVersion: EXTRACTION_PROMPT_VERSION,
459	        latencyMs: Date.now() - callStartedAt,
460	        success: false,
461	        error: err instanceof Error ? err.message : String(err),
462	      });
463	    }
464	    await db
465	      .update(extractionBatches)
466	      .set({
467	        status: 'failed',
468	        error: err instanceof Error ? err.message : String(err),
469	        finishedAt: new Date(),
470	      })
471	      .where(eq(extractionBatches.id, batch.id));
472	    await db
473	      .update(messages)
474	      .set({
475	        extractionStatus: 'failed',
476	        extractionError: err instanceof Error ? err.message : String(err),
477	      })
478	      .where(inArray(messages.id, segmentIds));
479	    outcome.messagesProcessed = segmentIds.length;
480	    return outcome;
481	  }
482	
483	  if (!modelOutput) return outcome;
484	
485	  // 4. Delegate per-candidate validation + promotion + final batch/message
486	  //    status updates to the shared processSegmentOutput function so the
487	  //    batch-drain worker can run identical logic on retrieved Batch API
488	  //    results without duplicating any of it.
489	  return processSegmentOutput({
490	    db,
491	    route,
492	    activeTopDomainIds,
493	    entityRegistry,
494	    segment,
495	    extractionBatchId: batch.id,
496	    modelRunId: modelRunId!,
497	    sourceHash,
498	    modelOutput,
499	    initialOutcome: outcome,
500	  });
501	}
502	
503	// ─────────────────────────────────────────────────────────────────────────
504	// processSegmentOutput — shared per-segment post-model-call processing
505	//
506	// Runs the candidate-before-claim pipeline (R5 quote validation, R5.5
507	// taxonomy validation, sensitivity gate, executePromotion) against an
508	// already-produced ExtractionOutput. Called by BOTH the sync path
509	// (claim-extraction.ts processSegment, immediately after the model call)
510	// AND the batch-drain path (claim-extraction-batch-drain.ts, after pulling
511	// results from the provider Batch API).
512	//
513	// Preconditions the caller must satisfy:
514	//   - extraction_batches row exists (extractionBatchId), in pending_model
515	//     or model_complete status
516	//   - model_runs row exists (modelRunId), with success=true
517	//   - modelOutput parses as ExtractionOutputSchema
518	//
519	// Postconditions:
520	//   - For each claim in modelOutput: extraction_candidates + evidence rows
521	//     inserted, validators run, executePromotion attempted
522	//   - extraction_batches.status updated to 'validation_complete' (or
523	//     'failed_validation_loop' if the circuit breaker tripped)
524	//   - All segment messages marked extraction_status='complete'
525	// ─────────────────────────────────────────────────────────────────────────
526	
527	export interface ProcessSegmentOutputArgs {
528	  db: OracleDb;
529	  route: OracleModelRoute;
530	  activeTopDomainIds: string[];
531	  entityRegistry: RegistryEntity[];
532	  segment: FormattedMessage[];
533	  extractionBatchId: string;
534	  modelRunId: string;
535	  sourceHash: string;
536	  modelOutput: ExtractionOutput;
537	  /** Sync caller passes its accumulator so candidatesStaged etc. roll up. */
538	  initialOutcome?: SegmentOutcome;
539	}
540	
541	export async function processSegmentOutput(
542	  args: ProcessSegmentOutputArgs,
543	): Promise<SegmentOutcome> {
544	  const {
545	    db, route, activeTopDomainIds, entityRegistry, segment,
546	    extractionBatchId, modelRunId, sourceHash, modelOutput,
547	  } = args;
548	  const segmentIds = segment.map((m) => m.id);
549	  const batch = { id: extractionBatchId };
550	  const outcome: SegmentOutcome = args.initialOutcome ?? {
551	    candidatesStaged: 0,
552	    claimsPromoted: 0,
553	    duplicatesAppended: 0,
554	    rejections: 0,
555	    circuitBreakerTripped: false,
556	    messagesProcessed: 0,
557	  };
558	
559	  // Stage candidates + evidence, run R5/R5.5 validators, run promotion.
560	  let consecutiveQuoteFailureCount = 0;
561	  let validationAttemptCount = 0;
562	
563	  for (const extracted of modelOutput.claims) {
564	    validationAttemptCount += 1;
565	
566	    // Insert the candidate row.
567	    const proposedTopDomainIds = mapLegacyDomainsToTopDomains(
568	      extracted.domains as KnowledgeDomain[],
569	    );
570	    const [candidate] = await db
571	      .insert(extractionCandidates)
572	      .values({
573	        extractionBatchId: batch.id,
574	        status: 'pending_validation',
575	        claimType: extracted.claimType,
576	        summary: extracted.summary,
577	        impactScore: extracted.impactScore,
578	        confidenceScore: extracted.confidenceScore,
579	        domains: proposedTopDomainIds satisfies TopLevelDomainId[],
580	        // P2 #1 — proposedEntities now sourced from the model (was hardcoded
581	        // empty pre-prompt-2.0.0). Empty array if the claim references no
582	        // proper-noun entities.
583	        proposedEntities: (extracted.proposedEntities ?? []).map((e) => ({
584	          entityType: e.entityType,
585	          rawString: e.rawString,
586	        })),
587	        stance: legacyStanceToCandidateStance(extracted.semanticRole),
588	        // P1 #2 — sensitivityFlags now sourced from the model. Was hardcoded
589	        // false on every claim pre-prompt-2.0.0, which meant the sensitivity
590	        // gate could never fire in production. Strict-mode definitions live
591	        // in EXTRACTION_SYSTEM_PROMPT.
592	        containsSensitivePersonalData:
593	          extracted.sensitivityFlags?.containsSensitivePersonalData ?? false,
594	        containsSensitiveHRData: extracted.sensitivityFlags?.containsSensitiveHRData ?? false,
595	        isPersonalConflict: extracted.sensitivityFlags?.isPersonalConflict ?? false,
596	        sensitivityReason: extracted.sensitivityFlags?.sensitivityReason ?? null,
597	        requiresReview: extracted.requiresReview,
598	        reviewReason: extracted.requiresReview ? 'extractor requested review' : null,
599	        rawCandidateJson: extracted as unknown as Record<string, unknown>,
600	      })
601	      .returning({ id: extractionCandidates.id });
602	    if (!candidate) {
603	      console.warn('[claim-extraction] candidate insert returned no row — skipping');
604	      continue;
605	    }
606	    outcome.candidatesStaged += 1;
607	
608	    // Insert evidence (single row per candidate for now — the extraction
609	    // schema only emits one quote per claim).
610	    const sourceMsg = segment.find((m) => m.id === extracted.evidence.sourceMessageId);
611	    const sourcePointerCheck = validateSourcePointer({
612	      sourceType: 'message',
613	      sourceMessageId: extracted.evidence.sourceMessageId,
614	    });
615	    if (!sourcePointerCheck.ok || !sourceMsg) {
616	      await db.insert(extractionValidationResults).values({
617	        candidateId: candidate.id,
618	        checkName: sourcePointerCheck.failedCheckName ?? 'source_exists',
619	        status: 'fail',
620	        detail: !sourceMsg
621	          ? `sourceMessageId ${extracted.evidence.sourceMessageId} not in segment`
622	          : sourcePointerCheck.detail,
623	      });
624	      await db
625	        .update(extractionCandidates)
626	        .set({
627	          status: 'validation_failed',
628	          validationError: 'source pointer invalid',
629	          validatedAt: new Date(),
630	        })
631	        .where(eq(extractionCandidates.id, candidate.id));
632	      outcome.rejections += 1;
633	      continue;
634	    }
635	
636	    const [evRow] = await db
637	      .insert(extractionCandidateEvidence)
638	      .values({
639	        candidateId: candidate.id,
640	        sourceType: 'message',
641	        sourceMessageId: extracted.evidence.sourceMessageId,
642	        assertedByEmployeeId:
643	          (segment.find((m) => m.id === extracted.evidence.sourceMessageId) as
644	            | (FormattedMessage & { employeeId?: string })
645	            | undefined)?.employeeId ?? null,
646	        exactQuoteProvided: extracted.evidence.exactQuote,
647	        validationStatus: 'pending',
648	        confidence: extracted.evidence.confidence,
649	      })
650	      .returning({ id: extractionCandidateEvidence.id });
651	    if (!evRow) {
652	      console.warn('[claim-extraction] candidate evidence insert returned no row — skipping');
653	      continue;
654	    }
655	
656	    // R5 — quote validation. Messages (incl. Teams-transcript utterances) get a
657	    // lenient policy: normalize whitespace/quotes, plus a fuzzy fallback that
658	    // tolerates the model paraphrasing disfluent speech while still anchoring
659	    // the evidence to the real utterance. See DECISIONS.md D-transcript-fuzzy-quote.
660	    const quoteRes = validateQuote({
661	      sourceText: sourceMsg.content,
662	      exactQuoteProvided: extracted.evidence.exactQuote,
663	      normalizationPolicy: {
664	        allowCRLF: true,
665	        allowSmartQuotes: true,
666	        allowWhitespaceCollapse: true,
667	        allowLeadingTrailingTrim: true,
668	      },
669	      allowFuzzy: true,
670	    });
671	    await db
672	      .update(extractionCandidateEvidence)
673	      .set({
674	        validationStatus: quoteRes.validationStatus,
675	        validationMethod: quoteRes.validationMethod,
676	        validatedExactQuote: quoteRes.validatedExactQuote ?? null,
677	        validatedCharStart: quoteRes.validatedCharStart ?? null,
678	        validatedCharEnd: quoteRes.validatedCharEnd ?? null,
679	        validatedAt: new Date(),
680	        validationError:
681	          quoteRes.verdict === 'exact_match' || quoteRes.verdict === 'normalized_match'
682	            ? null
683	            : quoteRes.detail,
684	      })
685	      .where(eq(extractionCandidateEvidence.id, evRow.id));
686	    await db.insert(extractionValidationResults).values({
687	      candidateId: candidate.id,
688	      candidateEvidenceId: evRow.id,
689	      checkName: quoteRes.failedCheckName ?? 'quote_exact_match',
690	      status:
691	        quoteRes.verdict === 'exact_match' || quoteRes.verdict === 'normalized_match'
692	          ? 'pass'
693	          : 'fail',
694	      detail: quoteRes.detail,
695	    });
696	
697	    if (quoteRes.verdict !== 'exact_match' && quoteRes.verdict !== 'normalized_match') {
698	      consecutiveQuoteFailureCount += 1;
699	      await db
700	        .update(extractionCandidates)
701	        .set({
702	          status: 'validation_failed',
703	          validationError: quoteRes.detail,
704	          validatedAt: new Date(),
705	        })
706	        .where(eq(extractionCandidates.id, candidate.id));
707	      outcome.rejections += 1;
708	
709	      // Circuit-breaker check after each failure.
710	      const cbDecision = decideCircuitBreaker({
711	        validationAttemptCount,
712	        consecutiveQuoteFailureCount,
713	      });
714	      if (cbDecision.kind === 'trip_breaker') {
715	        await db
716	          .update(extractionBatches)
717	          .set({
718	            status: 'failed_validation_loop',
719	            consecutiveQuoteFailureCount,
720	            validationAttemptCount,
721	            finishedAt: new Date(),
722	          })
723	          .where(eq(extractionBatches.id, batch.id));
724	        await db.insert(extractionValidationResults).values({
725	          candidateId: candidate.id,
726	          checkName: cbDecision.validationResultToWrite.checkName,
727	          status: cbDecision.validationResultToWrite.status,
728	          detail: cbDecision.validationResultToWrite.detail,
729	          metadataJson: {
730	            routeId: route.routeId,
731	            modelRunIdAttempted: modelRunId,
732	            sourceHash,
733	          },
734	        });
735	        outcome.circuitBreakerTripped = true;
736	        break; // stop processing this batch
737	      }
738	      continue;
739	    }
740	
741	    // Quote passed → reset the consecutive failure counter.
742	    consecutiveQuoteFailureCount = 0;
743	
744	    // R5.5 — taxonomy validation. proposedEntities sourced from prompt-2.0.0
745	    // (P2 #1). The resolver picks up licensor-vs-vendor type mismatches.
746	    const taxRes = validateTaxonomy({
747	      proposedTopDomainIds,
748	      activeTopDomainIds,
749	      proposedEntities: (extracted.proposedEntities ?? []).map((e) => ({
750	        entityType: e.entityType as EntityType,
751	        rawString: e.rawString,
752	      })),
753	      entityRegistry,
754	    });
755	    await db.insert(extractionValidationResults).values({
756	      candidateId: candidate.id,
757	      checkName: 'domain_valid',
758	      status: taxRes.ok ? 'pass' : 'fail',
759	      detail: taxRes.ok
760	        ? `Top-domains validated: ${taxRes.validTopDomainIds.join(', ')}`
761	        : taxRes.failures.map((f) => f.detail).join('; '),
762	    });
763	
764	    // Regardless of overall taxRes.ok, stage any entity proposals so admin
765	    // can review unknown entities or type-mismatch corrections.
766	    // stageEntityProposal() uses pg_trgm fuzzy-dedup: near-duplicate surfaces
767	    // (similarity >= 0.85) increment proposal_count instead of creating new rows.
768	    for (const p of taxRes.entityProposalsToCreate) {
769	      await stageEntityProposal(db, {
770	        proposedEntityType: p.proposedEntityType,
771	        proposedCanonicalValue: p.proposedCanonicalValue,
772	        rawString: p.rawString,
773	        observedInSourceType: 'claim_candidate',
774	        observedInSourceId: candidate.id,
775	        proposedByModelRunId: modelRunId,
776	      });
777	    }
778	
779	    if (!taxRes.ok) {
780	      await db
781	        .update(extractionCandidates)
782	        .set({
783	          status: 'validation_failed',
784	          validationError: taxRes.failureSummary ?? 'taxonomy invalid',
785	          validatedAt: new Date(),
786	        })
787	        .where(eq(extractionCandidates.id, candidate.id));
788	      outcome.rejections += 1;
789	      continue;
790	    }
791	
792	    // P1 #2 — Sensitivity gate. If the model flagged any sensitivity, the
793	    // candidate is quarantined here and never reaches promotion. The
794	    // candidate row is preserved with the model's reason so admin can
795	    // review it via /admin/ai/candidates → "Sensitive" tab.
796	    const sensitivityFired =
797	      extracted.sensitivityFlags?.containsSensitiveHRData === true ||
798	      extracted.sensitivityFlags?.containsSensitivePersonalData === true ||
799	      extracted.sensitivityFlags?.isPersonalConflict === true;
800	    if (sensitivityFired) {
801	      await db.insert(extractionValidationResults).values({
802	        candidateId: candidate.id,
803	        checkName: 'sensitivity_gate',
804	        status: 'fail',
805	        detail: extracted.sensitivityFlags?.sensitivityReason ?? 'extractor flagged sensitive content',
806	        metadataJson: {
807	          containsSensitiveHRData: extracted.sensitivityFlags?.containsSensitiveHRData ?? false,
808	          containsSensitivePersonalData:
809	            extracted.sensitivityFlags?.containsSensitivePersonalData ?? false,
810	          isPersonalConflict: extracted.sensitivityFlags?.isPersonalConflict ?? false,
811	        },
812	      });
813	      await db
814	        .update(extractionCandidates)
815	        .set({
816	          status: 'quarantined_sensitive',
817	          validationError: extracted.sensitivityFlags?.sensitivityReason ?? 'sensitive content flagged by extractor',
818	          validatedAt: new Date(),
819	        })
820	        .where(eq(extractionCandidates.id, candidate.id));
821	      outcome.rejections += 1;
822	      continue;
823	    }
824	
825	    // Sensitivity gate passed → record the pass row for the audit trail.
826	    await db.insert(extractionValidationResults).values({
827	      candidateId: candidate.id,
828	      checkName: 'sensitivity_gate',
829	      status: 'pass',
830	      detail: 'extractor reported no sensitive content',
831	    });
832	
833	    // Mark candidate validated; the executor re-reads it inside the lock.
834	    await db
835	      .update(extractionCandidates)
836	      .set({ status: 'validated', validatedAt: new Date() })
837	      .where(eq(extractionCandidates.id, candidate.id));
838	
839	    const validatedQuote = quoteRes.validatedExactQuote ?? extracted.evidence.exactQuote;
840	    const candidateHash = computeCandidateHash({
841	      summary: extracted.summary,
842	      topDomainIds: taxRes.validTopDomainIds,
843	      validatedQuotes: [validatedQuote],
844	      sourcePointers: [`message:${extracted.evidence.sourceMessageId}`],
845	    });
846	
847	    // executePromotion re-reads the candidate row + validated evidence
848	    // INSIDE the advisory lock. We pass only the auxiliary inputs that
849	    // can't be reconstructed from candidate-table state: taxonomy
850	    // validation result (depends on the live entities/top-domains
851	    // registries) and metadata (caller-computed per call).
852	    try {
853	      const result = await executePromotion({
854	        db,
855	        candidateId: candidate.id,
856	        candidateHash,
857	        auxiliaryInputs: { taxonomy: taxRes },
858	        modelRunId: modelRunId ?? undefined,
859	      });
860	      if (result.outcome === 'inserted_new_claim') outcome.claimsPromoted += 1;
861	      else if (result.outcome === 'appended_to_existing_claim') outcome.duplicatesAppended += 1;
862	      else outcome.rejections += 1;
863	    } catch (promErr) {
864	      if (promErr instanceof AdvisoryLockBusyError) {
865	        // Skip — another worker has the lock. Candidate stays 'validated';
866	        // the next cron run will pick it up.
867	        await db.insert(extractionValidationResults).values({
868	          candidateId: candidate.id,
869	          checkName: 'duplicate_promotion_lock',
870	          status: 'skipped',
871	          detail: 'Advisory lock busy; another worker holds it.',
872	        });
873	      } else {
874	        await db.insert(extractionValidationResults).values({
875	          candidateId: candidate.id,
876	          checkName: 'promotion_transaction',
877	          status: 'fail',
878	          detail: promErr instanceof Error ? promErr.message : String(promErr),
879	        });
880	        outcome.rejections += 1;
881	      }
882	    }
883	  } // end claims loop
884	
885	  if (!outcome.circuitBreakerTripped) {
886	    await db
887	      .update(extractionBatches)
888	      .set({
889	        status: 'validation_complete',
890	        consecutiveQuoteFailureCount,
891	        validationAttemptCount,
892	        finishedAt: new Date(),
893	      })
894	      .where(eq(extractionBatches.id, batch.id));
895	  }
896	
897	  // Mark messages complete. Even when individual candidates failed, the
898	  // segment itself was processed; failed candidates are kept staged for
899	  // admin review separately.
900	  await db
901	    .update(messages)
902	    .set({ extractionStatus: 'complete', extractedAt: new Date() })
903	    .where(inArray(messages.id, segmentIds));
904	  outcome.messagesProcessed = segmentIds.length;
905	
906	  return outcome;
907	}
