961	export function groupIntoSegments(
962	  pendingMessages: Array<{
963	    id: string;
964	    channelId: string;
965	    employeeId: string | null;
966	    role: 'user' | 'assistant' | 'system' | string;
967	    content: string;
968	    createdAt: Date;
969	    authorName: string | null;
970	  }>,
971	): FormattedMessage[][] {
972	  const byChannel = new Map<string, typeof pendingMessages>();
973	  for (const m of pendingMessages) {
974	    const list = byChannel.get(m.channelId) ?? [];
975	    list.push(m);
976	    byChannel.set(m.channelId, list);
977	  }
978	
979	  const allSegments: FormattedMessage[][] = [];
980	
981	  for (const [_channelId, channelMessages] of byChannel) {
982	    channelMessages.sort(
983	      (a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime(),
984	    );
985	    const segments: FormattedMessage[][] = [];
986	    let current: FormattedMessage[] = [];
987	
988	    for (const m of channelMessages) {
989	      if (current.length > 0) {
990	        const last = current[current.length - 1]!;
991	        const gap = new Date(m.createdAt).getTime() - new Date(last.createdAt).getTime();
992	        if (gap > SEGMENT_GAP_MS) {
993	          segments.push(current);
994	          current = [];
995	        }
996	      }
997	      current.push({
998	        id: m.id,
999	        role: m.role as 'user' | 'assistant' | 'system',
1000	        content: m.content,
1001	        authorName: m.authorName ?? null,
1002	        createdAt: new Date(m.createdAt),
1003	      });
1004	    }
1005	    if (current.length > 0) segments.push(current);
1006	    allSegments.push(...segments);
1007	  }
1008	
1009	  return allSegments;
1010	}
