1	// D14 — Claim extraction submit task (Batch API path)
2	//
3	// Cron: every 4 hours, same as the sync claim-extraction worker. Bails when
4	// settings.extraction_dispatch_mode !== 'batch'. The sync worker has a
5	// mirror-image bail when the flag IS 'batch', so the two paths never both
6	// process the same messages.
7	//
8	// Flow:
9	//   1. Read the flag — bail if not 'batch'
10	//   2. Resolve the extraction route + check its adapter supports batch
11	//   3. Pull pending user messages (BATCH_SIZE), mark them 'processing'
12	//   4. Group into 60-minute conversation segments
13	//   5. For each segment: compile the prompt plan, insert extraction_batches
14	//      and oracle_context_packs rows
15	//   6. Build BatchRequest[] (customId = extraction_batches.id)
16	//   7. Call adapter.submitBatch — submits the JSONL to OpenAI / GCS for Vertex
17	//   8. Insert provider_batch_jobs row with the providerBatchId + metadata
18	//   9. Link all extraction_batches rows to the provider_batch_jobs row
19	//
20	// The drain task (claim-extraction-batch-drain.ts) is what runs validation +
21	// promotion when the batch completes. This task only submits.
22	
23	import { schedules } from '@trigger.dev/sdk/v3';
24	import { and, eq, inArray } from 'drizzle-orm';
25	import { createHash } from 'node:crypto';
26	import { getDirectDb } from '@oracle/db/client';
27	import {
28	  employees,
29	  extractionBatches,
30	  jobRuns,
31	  messages,
32	  oracleContextPacks,
33	  providerBatchJobs,
34	  settings,
35	} from '@oracle/db';
36	import {
37	  buildStandardAdapters,
38	  OracleAIClient,
39	  supportsBatch,
40	  zodToJsonSchema,
41	  makeBlock,
42	  EXTRACTION_SYSTEM_PROMPT,
43	  EXTRACTION_PROMPT_VERSION,
44	  ExtractionOutputSchema,
45	  formatConversationSegment,
46	  type BatchRequest,
47	  type FormattedMessage,
48	} from '@oracle/ai';
49	import {
50	  BATCH_SIZE,
51	  buildContextPackInsert,
52	  groupIntoSegments,
53	  resolveExtractionRoute,
54	} from './claim-extraction';
55	
56	export interface BatchSubmitTotals {
57	  ok: boolean;
58	  skipped: boolean;
59	  reason?: string;
60	  segmentsSubmitted: number;
61	  providerBatchId?: string;
62	}
63	
64	export async function runClaimExtractionBatchSubmitOnce(
65	  triggerRunId: string,
66	): Promise<BatchSubmitTotals> {
67	  const db = getDirectDb();
68	  const startedAt = new Date();
69	
70	  const [jobRun] = await db
71	    .insert(jobRuns)
72	    .values({
73	      triggerRunId,
74	      jobType: 'claim-extraction-batch-submit',
75	      status: 'running',
76	      startedAt,
77	      inputJson: { batchSize: BATCH_SIZE },
78	    })
79	    .returning({ id: jobRuns.id });
80	  if (!jobRun) throw new Error('[claim-extraction-batch-submit] failed to insert job_runs row');
81	
82	  const finish = async (output: Record<string, unknown>) => {
83	    await db
84	      .update(jobRuns)
85	      .set({ status: 'complete', finishedAt: new Date(), outputJson: output })
86	      .where(eq(jobRuns.id, jobRun.id));
87	  };
88	
89	  // Hoisted so the catch can roll back the state this run created.
90	  // - claimedMessageIds: messages we flipped 'pending' → 'processing'.
91	  // - stagedBatchIds / stagedContextPackIds: extraction_batches +
92	  //   oracle_context_packs rows we inserted as part of staging segments.
93	  // - providerAccepted: flipped to true the moment adapter.submitBatch returns
94	  //   successfully. If a failure happens after that, the batch is live at the
95	  //   provider and the staging rows are still needed (drain finds them by
96	  //   customId from the batch result, not by provider_batch_job_id), so we
97	  //   leave them in place and log loudly instead of cleaning up.
98	  let claimedMessageIds: string[] = [];
99	  const stagedBatchIds: string[] = [];
100	  const stagedContextPackIds: string[] = [];
101	  let providerAccepted = false;
102	  let providerBatchIdForRecovery: string | null = null;
103	  let providerBatchJobInserted = false;
104	
105	  try {
106	    // 1. Dispatch-mode gate — mirror image of the sync worker.
107	    const dispatchModeRow = await db
108	      .select({ value: settings.value })
109	      .from(settings)
110	      .where(eq(settings.key, 'extraction_dispatch_mode'))
111	      .limit(1);
112	    const dispatchMode = (dispatchModeRow[0]?.value as string | undefined) ?? 'sync';
113	    if (dispatchMode !== 'batch') {
114	      await finish({ skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}` });
115	      return { ok: true, skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}`, segmentsSubmitted: 0 };
116	    }
117	
118	    // 2. Resolve route + check adapter capability.
119	    const route = await resolveExtractionRoute(db);
120	    const adapters = buildStandardAdapters();
121	    const adapter = adapters[route.provider];
122	    if (!adapter) {
123	      await finish({ skipped: true, reason: `no adapter registered for provider ${route.provider}` });
124	      return { ok: true, skipped: true, reason: `no adapter for ${route.provider}`, segmentsSubmitted: 0 };
125	    }
126	    if (!supportsBatch(adapter)) {
127	      await finish({ skipped: true, reason: `adapter ${route.provider} does not implement Batch API` });
128	      return { ok: true, skipped: true, reason: `adapter ${route.provider} does not support batch`, segmentsSubmitted: 0 };
129	    }
130	
131	    // 3. Pull pending messages.
132	    const pendingMessages = await db
133	      .select({
134	        id: messages.id,
135	        channelId: messages.channelId,
136	        employeeId: messages.employeeId,
137	        role: messages.role,
138	        content: messages.content,
139	        createdAt: messages.createdAt,
140	        authorName: employees.name,
141	      })
142	      .from(messages)
143	      .leftJoin(employees, eq(employees.id, messages.employeeId))
144	      .where(and(eq(messages.extractionStatus, 'pending'), eq(messages.role, 'user')))
145	      .orderBy(messages.createdAt)
146	      .limit(BATCH_SIZE);
147	
148	    if (pendingMessages.length === 0) {
149	      await finish({ segmentsSubmitted: 0, reason: 'no pending messages' });
150	      return { ok: true, skipped: false, segmentsSubmitted: 0 };
151	    }
152	
153	    // 4. Mark as 'processing' for idempotency.
154	    const messageIds = pendingMessages.map((m) => m.id);
155	    claimedMessageIds = messageIds;
156	    await db
157	      .update(messages)
158	      .set({ extractionStatus: 'processing' })
159	      .where(inArray(messages.id, messageIds));
160	
161	    // 5. Group into segments + 6. Build extraction_batches + context_packs + BatchRequest list.
162	    const segments = groupIntoSegments(pendingMessages);
163	    const client = new OracleAIClient({ adapters, fallbackOnError: false });
164	    const requests: BatchRequest[] = [];
165	    const allMessageIdsForFailure: string[] = [];
166	
167	    for (const segment of segments) {
168	      const segmentIds = segment.map((m) => m.id);
169	      allMessageIdsForFailure.push(...segmentIds);
170	      const userMessages = segment.filter((m) => m.role === 'user');
171	      if (userMessages.length === 0) {
172	        // Skip empty segments at submit time — mark messages as 'skipped'.
173	        await db
174	          .update(messages)
175	          .set({ extractionStatus: 'skipped', extractedAt: new Date() })
176	          .where(inArray(messages.id, segmentIds));
177	        continue;
178	      }
179	
180	      const formatted = formatConversationSegment(segment);
181	      const blocks = [
182	        makeBlock({
183	          id: 'extraction-system',
184	          label: 'Extraction system prompt',
185	          kind: 'stable_system',
186	          content: EXTRACTION_SYSTEM_PROMPT,
187	          reasonIncluded: 'extraction prompt v' + EXTRACTION_PROMPT_VERSION,
188	        }),
189	        makeBlock({
190	          id: 'segment',
191	          label: 'Conversation segment to extract from',
192	          kind: 'dynamic_input',
193	          content: formatted,
194	          reasonIncluded: `segment of ${segment.length} message(s) in this batch`,
195	        }),
196	      ];
197	      const plan = client.compile({
198	        taskType: 'message_claim_extraction',
199	        routeId: route.routeId,
200	        promptVersion: EXTRACTION_PROMPT_VERSION,
201	        blocks,
202	        observability: { includedMessageIds: segmentIds },
203	      });
204	      const sourceHash = createHash('sha256').update(formatted, 'utf8').digest('hex');
205	
206	      // Stage extraction_batches row in pending_model status (no model_run_id
207	      // yet — that gets filled in at drain time when results come back).
208	      const [batch] = await db
209	        .insert(extractionBatches)
210	        .values({
211	          jobRunId: jobRun.id,
212	          batchType: 'message_segment',
213	          status: 'pending_model',
214	          sourceMessageIds: segmentIds,
215	          sourceHash,
216	          modelRunIdsAttempted: [],
217	          routeIdsAttempted: [route.routeId],
218	        })
219	        .returning({ id: extractionBatches.id });
220	      if (!batch) throw new Error('[batch-submit] failed to insert extraction_batches row');
221	      // Track for rollback immediately — if the context_pack insert below
222	      // throws, this row is already orphaned and the catch needs to delete it.
223	      stagedBatchIds.push(batch.id);
224	
225	      const [contextPack] = await db
226	        .insert(oracleContextPacks)
227	        .values(buildContextPackInsert(plan))
228	        .returning({ id: oracleContextPacks.id });
229	      if (!contextPack) throw new Error('[batch-submit] failed to insert oracle_context_packs row');
230	      stagedContextPackIds.push(contextPack.id);
231	
232	      await db
233	        .update(extractionBatches)
234	        .set({ contextPackId: contextPack.id })
235	        .where(eq(extractionBatches.id, batch.id));
236	
237	      requests.push({
238	        customId: batch.id, // extraction_batches.id IS the customId so drain can map results
239	        plan,
240	      });
241	    }
242	
243	    if (requests.length === 0) {
244	      await finish({ segmentsSubmitted: 0, reason: 'all segments were user-message-free; no batch submitted' });
245	      return { ok: true, skipped: false, segmentsSubmitted: 0 };
246	    }
247	
248	    // 7. Submit batch via adapter.
249	    const jsonSchema = zodToJsonSchema(ExtractionOutputSchema);
250	    const submitResult = await adapter.submitBatch!({
251	      route,
252	      requests,
253	      jsonSchema,
254	    });
255	    // The provider has accepted the batch — from here on, staging rows MUST
256	    // survive any catch path because the drain task will need them to map
257	    // results back via customId.
258	    providerAccepted = true;
259	    providerBatchIdForRecovery = submitResult.providerBatchId;
260	
261	    // 8. Insert provider_batch_jobs row.
262	    const [batchJob] = await db
263	      .insert(providerBatchJobs)
264	      .values({
265	        provider: route.provider,
266	        providerBatchId: submitResult.providerBatchId,
267	        status: 'submitted',
268	        taskType: 'message_claim_extraction',
269	        routeId: route.routeId,
270	        modelId: route.modelId,
271	        requestCount: requests.length,
272	        providerMetadataJson: submitResult.providerMetadata,
273	      })
274	      .returning({ id: providerBatchJobs.id });
275	    if (!batchJob) throw new Error('[batch-submit] failed to insert provider_batch_jobs row');
276	    providerBatchJobInserted = true;
277	
278	    // 9. Link extraction_batches rows to the batch job.
279	    await db
280	      .update(extractionBatches)
281	      .set({ providerBatchJobId: batchJob.id })
282	      .where(inArray(extractionBatches.id, stagedBatchIds));
283	
284	    await finish({
285	      segmentsSubmitted: requests.length,
286	      providerBatchId: submitResult.providerBatchId,
287	      providerBatchJobId: batchJob.id,
288	    });
289	    return {
290	      ok: true,
291	      skipped: false,
292	      segmentsSubmitted: requests.length,
293	      providerBatchId: submitResult.providerBatchId,
294	    };
295	  } catch (err) {
296	    const errMsg = err instanceof Error ? err.message : String(err);
297	
298	    // Two failure regimes:
299	    //
300	    //  (a) providerAccepted === false: the failure happened before the
301	    //      provider accepted the batch. Nothing is live upstream. Roll back
302	    //      everything this run created — messages back to pending, staged
303	    //      extraction_batches + oracle_context_packs deleted — so the next
304	    //      cron tick gets a clean retry and the admin observability surface
305	    //      isn't littered with stale pending_model rows that will never get
306	    //      drained.
307	    //
308	    //  (b) providerAccepted === true but providerBatchJobInserted === false:
309	    //      the provider has an upstream batch, but Oracle has no durable row
310	    //      for the drain task to poll. That upstream batch is intentionally
311	    //      abandoned; reset local state so the next cron can submit a tracked
312	    //      retry instead of leaving messages stuck as 'processing'.
313	    //
314	    //  (c) providerBatchJobInserted === true: the provider batch is tracked.
315	    //      A failure after that point means messages stay 'processing' and
316	    //      staging rows MUST be kept — drain can recover by polling the job.
317	    if (!providerAccepted || !providerBatchJobInserted) {
318	      if (providerAccepted) {
319	        console.error(
320	          '[claim-extraction-batch-submit] provider accepted a batch but local provider_batch_jobs insert failed; abandoning upstream batch and resetting local state',
321	          { providerBatchId: providerBatchIdForRecovery, error: errMsg },
322	        );
323	      }
324	      if (claimedMessageIds.length > 0) {
325	        try {
326	          await db
327	            .update(messages)
328	            .set({ extractionStatus: 'pending' })
329	            .where(
330	              and(
331	                inArray(messages.id, claimedMessageIds),
332	                eq(messages.extractionStatus, 'processing'),
333	              ),
334	            );
335	        } catch (revertErr) {
336	          console.error(
337	            '[claim-extraction-batch-submit] failed to revert messages to pending',
338	            revertErr,
339	          );
340	        }
341	      }
342	      // Delete the FK child first (oracle_context_packs is referenced from
343	      // extraction_batches.context_pack_id), then the parent staging rows.
344	      // Both deletes are scoped to ids this run created, so they cannot
345	      // touch any other batch's state.
346	      if (stagedBatchIds.length > 0) {
347	        try {
348	          await db
349	            .delete(extractionBatches)
350	            .where(inArray(extractionBatches.id, stagedBatchIds));
351	        } catch (cleanupErr) {
352	          console.error(
353	            '[claim-extraction-batch-submit] failed to delete staged extraction_batches rows',
354	            cleanupErr,
355	          );
356	        }
357	      }
358	      if (stagedContextPackIds.length > 0) {
359	        try {
360	          await db
361	            .delete(oracleContextPacks)
362	            .where(inArray(oracleContextPacks.id, stagedContextPackIds));
363	        } catch (cleanupErr) {
364	          console.error(
