111	function chunkText(text: string, chunkSize = CHUNK_SIZE, overlap = CHUNK_OVERLAP): string[] {
112	  if (text.length <= chunkSize) return [text];
113	  const chunks: string[] = [];
114	  let start = 0;
115	  while (start < text.length) {
116	    const end = Math.min(start + chunkSize, text.length);
117	    chunks.push(text.slice(start, end));
118	    start += chunkSize - overlap;
119	    if (start >= text.length) break;
120	  }
121	  return chunks;
122	}
