131	async function extractTextFromXlsx(buffer: Buffer): Promise<string> {
132	  const XLSX = await import('xlsx');
133	  const workbook = XLSX.read(buffer, { type: 'buffer' });
134	  const lines: string[] = [];
135	  for (const sheetName of workbook.SheetNames) {
136	    lines.push(`[Sheet: ${sheetName}]`);
137	    const sheet = workbook.Sheets[sheetName];
138	    if (sheet) {
139	      const csv = XLSX.utils.sheet_to_csv(sheet);
140	      lines.push(csv);
141	    }
142	  }
143	  return lines.join('\n');
144	}
