158	async function processDocument(documentId: string, jobRunId: string): Promise<ProcessDocumentResult> {
159	  const db = getDirectDb();
160	  const client = buildOracleClient();
161	  const serviceSupabase = createServiceRoleClient();
162	  const outcome: ProcessDocumentResult = {
163	    chunksInserted: 0,
164	    candidatesStaged: 0,
165	    claimsPromoted: 0,
166	    duplicatesAppended: 0,
167	    rejections: 0,
168	  };
169	
170	  // 1. Load + mark processing.
171	  const [doc] = await db.select().from(documents).where(eq(documents.id, documentId)).limit(1);
172	  if (!doc) throw new Error(`Document ${documentId} not found`);
173	  if (doc.status === 'complete') {
174	    console.log(`[document-ingestion] ${documentId} already complete — skipping`);
175	    return outcome;
176	  }
177	  await db.update(documents).set({ status: 'processing' }).where(eq(documents.id, documentId));
178	
179	  const route = await resolveExtractionRoute(db);
180	  const activeTopDomainIds = await loadActiveTopDomainIds(db);
181	  const entityRegistry = await loadEntityRegistry(db);
182	
183	  // 2. Download.
184	  const { data: blob, error: downloadError } = await serviceSupabase.storage
185	    .from(doc.storageBucket)
186	    .download(doc.storagePath);
187	  if (downloadError || !blob) {
188	    throw new Error(
189	      `Storage download failed for ${doc.storagePath}: ${downloadError?.message ?? 'empty blob'}`,
190	    );
191	  }
192	  const buffer = Buffer.from(await blob.arrayBuffer());
193	  const fileBackedCachePath =
194	    route.provider === 'vertex' && buffer.length > VERTEX_FILE_CACHE_MIN_BYTES
195	      ? await materializeVertexCacheTempFile(buffer, doc.fileName)
196	      : null;
197	
198	  // 3. Parse.
199	  let rawText: string;
200	  try {
201	    if (doc.fileType === 'application/pdf') {
202	      rawText = await extractTextFromPdf(buffer);
203	    } else if (
204	      doc.fileType === 'application/vnd.ms-excel' ||
205	      doc.fileType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ||
206	      doc.fileType === 'text/csv'
207	    ) {
208	      rawText = await extractTextFromXlsx(buffer);
209	    } else if (doc.fileType.startsWith('text/')) {
210	      rawText = buffer.toString('utf-8');
211	    } else {
212	      console.warn(
213	        `[document-ingestion] unsupported file type ${doc.fileType} for doc ${documentId} — marking complete with note`,
214	      );
215	      await db
216	        .update(documents)
217	        .set({
218	          status: 'complete',
219	          processedAt: new Date(),
220	          processingError: `Unsupported file type: ${doc.fileType}`,
221	        })
222	        .where(eq(documents.id, documentId));
223	      return outcome;
224	    }
225	  } catch (parseErr) {
226	    throw new Error(
227	      `File parse failed for ${doc.fileName}: ${parseErr instanceof Error ? parseErr.message : String(parseErr)}`,
228	    );
229	  }
230	
231	  if (!rawText.trim()) {
232	    await db
233	      .update(documents)
234	      .set({ status: 'complete', processedAt: new Date(), processingError: 'No text extracted' })
235	      .where(eq(documents.id, documentId));
236	    return outcome;
237	  }
238	
239	  // 4. Chunk + embed + insert chunks (idempotent dedup by content hash).
240	  const textChunks = chunkText(rawText);
241	  let chunkVectors: (number[] | null)[] = [];
242	  try {
243	    const { vectors } = await embedMany(textChunks);
244	    chunkVectors = vectors;
245	  } catch (embedErr) {
246	    console.warn('[document-ingestion] embed failed; inserting chunks without vectors', embedErr);
247	    chunkVectors = textChunks.map(() => null);
248	  }
249	
250	  const insertedChunkIds: Array<{ id: string; text: string }> = [];
251	  for (let i = 0; i < textChunks.length; i++) {
252	    const text = textChunks[i]!;
253	    const contentHash = createHash('sha256').update(text).digest('hex');
254	    try {
255	      const [chunk] = await db
256	        .insert(documentChunks)
257	        .values({
258	          documentId,
259	          chunkIndex: i,
260	          rawText: text,
261	          tokenCount: Math.ceil(text.length / 4),
262	          contentHash,
263	          embedding: chunkVectors[i] ?? null,
264	          metadataJson: { fileType: doc.fileType, fileName: doc.fileName },
265	        })
266	        .onConflictDoNothing()
267	        .returning({ id: documentChunks.id });
268	      if (chunk) {
269	        outcome.chunksInserted += 1;
270	        insertedChunkIds.push({ id: chunk.id, text });
271	      }
272	    } catch (chunkErr) {
273	      console.error(`[document-ingestion] chunk ${i} insert failed:`, chunkErr);
274	    }
275	  }
276	
277	  if (insertedChunkIds.length === 0 || rawText.trim().length <= 20) {
278	    await db
279	      .update(documents)
280	      .set({ status: 'complete', processedAt: new Date() })
281	      .where(eq(documents.id, documentId));
282	    return outcome;
283	  }
284	
285	  // 5. Stage extraction_batches row.
286	  const truncatedText = rawText.slice(0, MAX_DOCUMENT_TEXT_CHARS);
287	  const sourceHash = createHash('sha256').update(truncatedText, 'utf8').digest('hex');
288	  const [batch] = await db
289	    .insert(extractionBatches)
290	    .values({
291	      jobRunId,
292	      batchType: 'document_page',
293	      status: 'pending_model',
294	      sourceDocumentChunkIds: insertedChunkIds.map((c) => c.id),
295	      sourceHash,
296	      modelRunIdsAttempted: [],
297	      routeIdsAttempted: [route.routeId],
298	    })
299	    .returning({ id: extractionBatches.id });
300	  if (!batch) throw new Error('[document-ingestion] failed to insert extraction_batches row');
301	
302	  // 6. Compile prompt + context pack. The document text becomes the dynamic
303	  //    block; the extraction system prompt + the document-specific addendum
304	  //    are stable.
305	  const documentNote =
306	    `\n\nNOTE: This is a DOCUMENT, not a conversation. Extract claims about operational processes, rules, systems, and dependencies described in the document.\nDocument name: ${doc.fileName}\nFile type: ${doc.fileType}`;
307	  const blocks = [
308	    makeBlock({
309	      id: 'extraction-system',
310	      label: 'Extraction system prompt + document addendum',
311	      kind: 'stable_system',
312	      content: EXTRACTION_SYSTEM_PROMPT + documentNote,
313	      reasonIncluded: 'extraction prompt v' + EXTRACTION_PROMPT_VERSION + ' (document mode)',
314	    }),
315	    makeBlock({
316	      id: 'document-text',
317	      label: 'Document content (truncated)',
318	      kind: 'retrieved_context',
319	      content: truncatedText,
320	      reasonIncluded: `${insertedChunkIds.length} chunks → truncated to ${truncatedText.length} chars`,
321	    }),
322	    makeBlock({
323	      id: 'document-request',
324	      label: 'Document extraction request',
325	      kind: 'dynamic_input',
326	      content:
327	        'Extract operational claims from the provided document corpus. Return only claims that are explicitly supported by the document text.',
328	      reasonIncluded: 'small dynamic request so the document corpus can be cached as reusable prefix',
329	    }),
330	  ];
331	  const plan = client.compile({
332	    taskType: 'document_claim_extraction',
333	    routeId: route.routeId,
334	    promptVersion: EXTRACTION_PROMPT_VERSION,
335	    blocks,
336	    observability: { includedDocumentChunkIds: insertedChunkIds.map((c) => c.id) },
337	  });
338	
339	  const [contextPack] = await db
340	    .insert(oracleContextPacks)
341	    .values(buildContextPackInsert(plan))
342	    .returning({ id: oracleContextPacks.id });
343	  if (!contextPack) throw new Error('[document-ingestion] failed to insert oracle_context_packs row');
344	  await db
345	    .update(extractionBatches)
346	    .set({ contextPackId: contextPack.id })
347	    .where(eq(extractionBatches.id, batch.id));
348	
349	  // 7. Call the model. The adapter now owns the real Vertex explicit-cache
350	  //    lifecycle, including cross-process reuse via provider_cached_content.
351	  let modelOutput: ExtractionOutput | null = null;
352	  let modelRunId: string | null = null;
353	  const callStartedAt = Date.now();
354	  try {
355	    const result = await client.runObject<ExtractionOutput>({
356	      taskType: 'document_claim_extraction',
357	      routeId: route.routeId,
358	      promptVersion: EXTRACTION_PROMPT_VERSION,
359	      blocks,
360	      schema: ExtractionOutputSchema,
361	      observability: { includedDocumentChunkIds: insertedChunkIds.map((c) => c.id) },
362	      providerOptions: {
363	        cache: {
364	          preferLongLivedCache: true,
365	          preferExplicitCache: route.provider === 'vertex',
366	          cacheTtlSeconds: 60 * 60,
367	          expectedReuseCount: 2,
368	          persistProviderCacheRecord: route.provider === 'vertex',
369	          sourceDescription: `${doc.fileName} (${doc.fileType})`,
370	          cleanupOwner: 'document-ingestion-worker',
371	          createdByJobRunId: jobRunId,
372	          latestPlannedReuseStep: 'document_claim_extraction',
373	          vertexFileCacheSource: fileBackedCachePath
374	            ? {
375	                localPath: fileBackedCachePath,
376	                mimeType: doc.fileType,
377	                fileName: doc.fileName,
378	                sourceHash,
379	              }
380	            : undefined,
381	        },
382	      },
383	    });
384	    const latencyMs = Date.now() - callStartedAt;
385	    const actualRouteId = result.routeId ?? route.routeId;
386	    const actualProvider = result.provider ?? route.provider;
387	    const actualModelId = result.modelId ?? route.modelId;
388	
389	    const [modelRun] = await db
390	      .insert(modelRuns)
391	      .values({
392	        taskType: 'document-ingestion',
393	        model: actualModelId,
394	        provider: actualProvider,
395	        promptVersion: EXTRACTION_PROMPT_VERSION,
396	        inputHash: plan.metadata.stablePrefixHash,
397	        inputTokens: result.usage.inputTokens ?? null,
398	        outputTokens: result.usage.outputTokens ?? null,
399	        latencyMs,
400	        success: result.validation.ok,
401	      })
402	      .returning({ id: modelRuns.id });
403	    if (!modelRun) throw new Error('[document-ingestion] failed to insert model_runs row');
404	    modelRunId = modelRun.id;
405	
406	    await db.insert(modelRunUsageDetails).values({
407	      modelRunId: modelRun.id,
408	      contextPackId: contextPack.id,
409	      routeId: actualRouteId,
410	      inputTokens: result.usage.inputTokens ?? null,
411	      cachedInputTokens: result.usage.cachedInputTokens ?? null,
412	      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
413	      outputTokens: result.usage.outputTokens ?? null,
414	      reasoningTokens: result.usage.reasoningTokens ?? null,
415	      providerRequestId: result.usage.providerRequestId ?? null,
416	      rawUsageJson: result.usage.rawUsageJson ?? null,
417	      fellBackFromRouteId: result.fellBackFromRouteId ?? null,
418	      fallbackReason: result.fallbackReason ?? null,
419	    });
420	    await db
421	      .update(oracleContextPacks)
422	      .set({ modelRunId: modelRun.id })
423	      .where(eq(oracleContextPacks.id, contextPack.id));
424	    await db
425	      .update(extractionBatches)
426	      .set({
427	        modelRunId: modelRun.id,
428	        modelRunIdsAttempted: [modelRun.id],
429	        rawModelOutput: result.object as unknown as Record<string, unknown>,
430	        status: result.validation.ok ? 'model_complete' : 'failed',
431	      })
432	      .where(eq(extractionBatches.id, batch.id));
433	
434	    if (!result.validation.ok) {
435	      throw new Error(
436	        '[document-ingestion] model output failed Zod schema validation: ' + result.validation.error.message,
437	      );
438	    }
439	    modelOutput = result.object;
440	  } catch (err) {
441	    if (!modelRunId) {
442	      await db.insert(modelRuns).values({
443	        taskType: 'document-ingestion',
444	        model: route.modelId,
445	        provider: route.provider,
446	        promptVersion: EXTRACTION_PROMPT_VERSION,
447	        latencyMs: Date.now() - callStartedAt,
448	        success: false,
449	        error: err instanceof Error ? err.message : String(err),
450	      });
451	    }
452	    await db
453	      .update(extractionBatches)
454	      .set({
455	        status: 'failed',
456	        error: err instanceof Error ? err.message : String(err),
457	        finishedAt: new Date(),
458	      })
459	      .where(eq(extractionBatches.id, batch.id));
460	    // Document still has chunks — mark complete with the error noted.
461	    await db
462	      .update(documents)
463	      .set({
464	        status: 'complete',
465	        processedAt: new Date(),
466	        processingError: err instanceof Error ? err.message : String(err),
467	      })
468	      .where(eq(documents.id, documentId));
469	    if (fileBackedCachePath) {
470	      await unlink(fileBackedCachePath).catch(() => undefined);
471	    }
472	    return outcome;
473	  }
474	
475	  // 9. For each extracted claim: stage candidate + evidence, validate,
476	  //    promote. The promoter writes claim_top_domains for the claim; we
477	  //    additionally write document_chunk_top_domains so retrieval works
478	  //    against the chunk independently.
479	  if (modelOutput) {
480	    for (const extracted of modelOutput.claims) {
481	      // Pick the chunk whose text contains the quote. If none does, the
482	      // quote validator will reject it as 'failed' anyway.
483	      const matchingChunk = insertedChunkIds.find((c) => c.text.includes(extracted.evidence.exactQuote));
484	      const chunkForEvidence = matchingChunk ?? insertedChunkIds[0]!;
485	
486	      const proposedTopDomainIds = mapLegacyDomainsToTopDomains(
487	        extracted.domains as KnowledgeDomain[],
488	      );
489	
490	      const [candidate] = await db
491	        .insert(extractionCandidates)
492	        .values({
493	          extractionBatchId: batch.id,
494	          status: 'pending_validation',
495	          claimType: extracted.claimType,
496	          summary: extracted.summary,
497	          impactScore: extracted.impactScore,
498	          confidenceScore: extracted.confidenceScore,
499	          domains: proposedTopDomainIds satisfies TopLevelDomainId[],
500	          // P2 #1 — proposedEntities now sourced from prompt-2.0.0.
501	          proposedEntities: (extracted.proposedEntities ?? []).map((e) => ({
502	            entityType: e.entityType,
503	            rawString: e.rawString,
504	          })),
505	          // P1 #2 — sensitivityFlags now sourced from prompt-2.0.0.
506	          containsSensitivePersonalData:
507	            extracted.sensitivityFlags?.containsSensitivePersonalData ?? false,
508	          containsSensitiveHRData: extracted.sensitivityFlags?.containsSensitiveHRData ?? false,
509	          isPersonalConflict: extracted.sensitivityFlags?.isPersonalConflict ?? false,
510	          sensitivityReason: extracted.sensitivityFlags?.sensitivityReason ?? null,
511	          requiresReview: extracted.requiresReview,
512	          reviewReason: extracted.requiresReview ? 'extractor requested review' : null,
513	          rawCandidateJson: extracted as unknown as Record<string, unknown>,
514	        })
515	        .returning({ id: extractionCandidates.id });
516	      if (!candidate) continue;
517	      outcome.candidatesStaged += 1;
518	
519	      // Stage candidate evidence (source_type='document_chunk').
520	      const sourcePointerRes = validateSourcePointer({
521	        sourceType: 'document_chunk',
522	        sourceDocumentChunkId: chunkForEvidence.id,
523	      });
524	      if (!sourcePointerRes.ok) {
525	        await db.insert(extractionValidationResults).values({
526	          candidateId: candidate.id,
527	          checkName: sourcePointerRes.failedCheckName ?? 'source_exists',
528	          status: 'fail',
529	          detail: sourcePointerRes.detail,
530	        });
531	        await db
532	          .update(extractionCandidates)
533	          .set({ status: 'validation_failed', validationError: 'source pointer invalid', validatedAt: new Date() })
534	          .where(eq(extractionCandidates.id, candidate.id));
535	        outcome.rejections += 1;
536	        continue;
537	      }
538	      const [evRow] = await db
539	        .insert(extractionCandidateEvidence)
540	        .values({
541	          candidateId: candidate.id,
542	          sourceType: 'document_chunk',
543	          sourceDocumentChunkId: chunkForEvidence.id,
544	          uploadedByEmployeeId: doc.uploaderId,
545	          exactQuoteProvided: extracted.evidence.exactQuote,
546	          validationStatus: 'pending',
547	          confidence: extracted.evidence.confidence,
548	          documentClass: null,
549	          processStage: null,
550	        })
551	        .returning({ id: extractionCandidateEvidence.id });
552	      if (!evRow) continue;
553	
554	      // Quote validation against the matching chunk's text.
555	      const quoteRes = validateQuote({
556	        sourceText: chunkForEvidence.text,
557	        exactQuoteProvided: extracted.evidence.exactQuote,
558	      });
559	      await db
560	        .update(extractionCandidateEvidence)
561	        .set({
562	          validationStatus: quoteRes.validationStatus,
563	          validationMethod: quoteRes.validationMethod,
564	          validatedExactQuote: quoteRes.validatedExactQuote ?? null,
565	          validatedCharStart: quoteRes.validatedCharStart ?? null,
566	          validatedCharEnd: quoteRes.validatedCharEnd ?? null,
567	          validatedAt: new Date(),
568	          validationError:
569	            quoteRes.verdict === 'exact_match' || quoteRes.verdict === 'normalized_match'
570	              ? null
571	              : quoteRes.detail,
572	        })
573	        .where(eq(extractionCandidateEvidence.id, evRow.id));
574	      await db.insert(extractionValidationResults).values({
575	        candidateId: candidate.id,
576	        candidateEvidenceId: evRow.id,
577	        checkName: quoteRes.failedCheckName ?? 'quote_exact_match',
578	        status:
579	          quoteRes.verdict === 'exact_match' || quoteRes.verdict === 'normalized_match'
580	            ? 'pass'
581	            : 'fail',
582	        detail: quoteRes.detail,
583	      });
584	
585	      if (quoteRes.verdict !== 'exact_match' && quoteRes.verdict !== 'normalized_match') {
586	        await db
587	          .update(extractionCandidates)
588	          .set({ status: 'validation_failed', validationError: quoteRes.detail, validatedAt: new Date() })
589	          .where(eq(extractionCandidates.id, candidate.id));
590	        outcome.rejections += 1;
591	        continue;
592	      }
593	
594	      // Taxonomy validation. proposedEntities sourced from prompt-2.0.0 (P2 #1).
595	      const taxRes = validateTaxonomy({
596	        proposedTopDomainIds,
597	        activeTopDomainIds,
598	        proposedEntities: (extracted.proposedEntities ?? []).map((e) => ({
599	          entityType: e.entityType as EntityType,
600	          rawString: e.rawString,
601	        })),
602	        entityRegistry,
603	      });
604	      await db.insert(extractionValidationResults).values({
605	        candidateId: candidate.id,
606	        checkName: 'domain_valid',
607	        status: taxRes.ok ? 'pass' : 'fail',
608	        detail: taxRes.ok
609	          ? `Top-domains validated: ${taxRes.validTopDomainIds.join(', ')}`
610	          : taxRes.failures.map((f) => f.detail).join('; '),
611	      });
612	      // Stage entity proposals regardless of overall taxRes.ok so admin can
613	      // review unknown entities surfaced by the model.
614	      // stageEntityProposal() uses pg_trgm fuzzy-dedup: near-duplicate surfaces
615	      // (similarity >= 0.85) increment proposal_count instead of creating new rows.
616	      for (const p of taxRes.entityProposalsToCreate) {
617	        await stageEntityProposal(db, {
618	          proposedEntityType: p.proposedEntityType,
619	          proposedCanonicalValue: p.proposedCanonicalValue,
620	          rawString: p.rawString,
621	          observedInSourceType: 'claim_candidate',
622	          observedInSourceId: candidate.id,
623	          proposedByModelRunId: modelRunId,
624	        });
625	      }
626	
627	      if (!taxRes.ok) {
628	        await db
629	          .update(extractionCandidates)
630	          .set({ status: 'validation_failed', validationError: taxRes.failureSummary ?? 'taxonomy invalid', validatedAt: new Date() })
631	          .where(eq(extractionCandidates.id, candidate.id));
632	        outcome.rejections += 1;
633	        continue;
634	      }
635	
636	      // P1 #2 — Sensitivity gate. Mirrors claim-extraction.ts.
637	      const sensitivityFired =
638	        extracted.sensitivityFlags?.containsSensitiveHRData === true ||
639	        extracted.sensitivityFlags?.containsSensitivePersonalData === true ||
640	        extracted.sensitivityFlags?.isPersonalConflict === true;
641	      if (sensitivityFired) {
642	        await db.insert(extractionValidationResults).values({
643	          candidateId: candidate.id,
644	          checkName: 'sensitivity_gate',
645	          status: 'fail',
646	          detail: extracted.sensitivityFlags?.sensitivityReason ?? 'extractor flagged sensitive content',
647	          metadataJson: {
648	            containsSensitiveHRData: extracted.sensitivityFlags?.containsSensitiveHRData ?? false,
649	            containsSensitivePersonalData:
650	              extracted.sensitivityFlags?.containsSensitivePersonalData ?? false,
651	            isPersonalConflict: extracted.sensitivityFlags?.isPersonalConflict ?? false,
652	          },
653	        });
654	        await db
655	          .update(extractionCandidates)
656	          .set({
657	            status: 'quarantined_sensitive',
658	            validationError:
659	              extracted.sensitivityFlags?.sensitivityReason ?? 'sensitive content flagged by extractor',
660	            validatedAt: new Date(),
661	          })
662	          .where(eq(extractionCandidates.id, candidate.id));
663	        outcome.rejections += 1;
664	        continue;
665	      }
666	      await db.insert(extractionValidationResults).values({
667	        candidateId: candidate.id,
668	        checkName: 'sensitivity_gate',
669	        status: 'pass',
670	        detail: 'extractor reported no sensitive content',
671	      });
672	
673	      // Mark validated; the executor re-reads the candidate + evidence
674	      // INSIDE the advisory lock. We pass only auxiliary inputs that can't
675	      // be reconstructed from candidate-table state.
676	      await db
677	        .update(extractionCandidates)
678	        .set({ status: 'validated', validatedAt: new Date() })
679	        .where(eq(extractionCandidates.id, candidate.id));
680	
681	      const validatedQuote = quoteRes.validatedExactQuote ?? extracted.evidence.exactQuote;
682	      const candidateHash = computeCandidateHash({
683	        summary: extracted.summary,
684	        topDomainIds: taxRes.validTopDomainIds,
685	        validatedQuotes: [validatedQuote],
686	        sourcePointers: [`document_chunk:${chunkForEvidence.id}`],
687	      });
688	
689	      try {
690	        const result = await executePromotion({
691	          db,
692	          candidateId: candidate.id,
693	          candidateHash,
694	          auxiliaryInputs: { taxonomy: taxRes },
695	          modelRunId: modelRunId ?? undefined,
696	        });
697	        if (result.outcome === 'inserted_new_claim') outcome.claimsPromoted += 1;
698	        else if (result.outcome === 'appended_to_existing_claim') outcome.duplicatesAppended += 1;
699	        else outcome.rejections += 1;
700	
701	        // Write document-level + chunk-level top-domain tags for retrieval.
702	        if (result.outcome !== 'recorded_rejection') {
703	          for (const topDomainId of taxRes.validTopDomainIds) {
704	            await db
705	              .insert(documentTopDomains)
706	              .values({
707	                documentId,
708	                topDomainId,
709	                assignmentReason: 'ingestion',
710	              })
711	              .onConflictDoNothing();
712	            await db
713	              .insert(documentChunkTopDomains)
714	              .values({
715	                documentChunkId: chunkForEvidence.id,
716	                topDomainId,
717	                assignmentReason: 'ingestion',
718	              })
719	              .onConflictDoNothing();
720	          }
721	        }
722	      } catch (promErr) {
723	        if (promErr instanceof AdvisoryLockBusyError) {
724	          await db.insert(extractionValidationResults).values({
725	            candidateId: candidate.id,
726	            checkName: 'duplicate_promotion_lock',
727	            status: 'skipped',
728	            detail: 'Advisory lock busy; another worker holds it.',
729	          });
730	        } else {
731	          await db.insert(extractionValidationResults).values({
732	            candidateId: candidate.id,
733	            checkName: 'promotion_transaction',
734	            status: 'fail',
735	            detail: promErr instanceof Error ? promErr.message : String(promErr),
736	          });
737	          outcome.rejections += 1;
738	        }
739	      }
740	    }
741	  }
742	
743	  // 10. Mark batch validation_complete.
744	  await db
745	    .update(extractionBatches)
746	    .set({ status: 'validation_complete', finishedAt: new Date() })
747	    .where(eq(extractionBatches.id, batch.id));
748	
749	  await db
750	    .update(documents)
751	    .set({ status: 'complete', processedAt: new Date() })
752	    .where(eq(documents.id, documentId));
753	
754	  if (fileBackedCachePath) {
755	    await unlink(fileBackedCachePath).catch(() => undefined);
756	  }
757	
758	  return outcome;
759	}
