780	async function loadActiveTopDomainIds(db: OracleDb): Promise<string[]> {
781	  const { sql } = await import('drizzle-orm');
782	  const rows = await db.execute<{ id: string }>(
783	    sql`SELECT id FROM knowledge_top_domains WHERE is_active = true`,
784	  );
785	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
786	  const list: Array<{ id: string }> = (rows as any).rows ?? (rows as any);
