99	// ─────────────────────────────────────────────────────────────────────────
100	// Proposal handlers
101	// ─────────────────────────────────────────────────────────────────────────
102	
103	type HandlerResult =
104	  | { applied: true; afterState: unknown }
105	  | { applied: false; reason: string };
106	
107	/** create_sub_topic: INSERT knowledge_sub_topics + link representative claims. */
108	async function handleCreateSubTopic(
109	  db: ReturnType<typeof getDirectDb>,
110	  payload: ProposalPayload,
111	): Promise<HandlerResult> {
112	  const topDomainId = payload.topDomainId as string | undefined;
113	  const proposedName = payload.proposedName as string | undefined;
114	  const purpose = payload.oneSentencePurpose as string | undefined;
115	  const centroid = payload.clusterCentroid as number[] | undefined;
116	  const representativeClaimIds = (payload.representativeClaimIds as string[] | undefined) ?? [];
117	
118	  if (!topDomainId || !proposedName) {
119	    return { applied: false, reason: 'payload missing topDomainId or proposedName' };
120	  }
121	
122	  const [inserted] = await db
123	    .insert(knowledgeSubTopics)
124	    .values({
125	      topDomainId,
126	      name: proposedName,
127	      description: purpose ?? null,
128	      centroid: centroid ?? null,
129	      memberCount: representativeClaimIds.length,
130	      reviewStatus: 'approved',
131	    })
132	    .onConflictDoNothing()
133	    .returning({ id: knowledgeSubTopics.id });
134	
135	  if (!inserted) {
136	    return {
137	      applied: false,
138	      reason: `knowledge_sub_topic (${topDomainId}, "${proposedName}") already exists — skipping`,
139	    };
140	  }
141	
142	  if (representativeClaimIds.length > 0) {
143	    await db
144	      .insert(claimSubTopics)
145	      .values(
146	        representativeClaimIds.map((claimId) => ({
147	          claimId,
148	          subTopicId: inserted.id,
149	          assignmentReason: 'cluster_seed',
150	          assignmentConfidence: '0.800',
151	        })),
152	      )
153	      .onConflictDoNothing();
154	  }
155	
156	  return {
157	    applied: true,
158	    afterState: {
159	      subTopicId: inserted.id,
160	      topDomainId,
161	      name: proposedName,
162	      linkedClaims: representativeClaimIds.length,
163	    },
164	  };
165	}
166	
167	/** reassign_claims: move claims from one sub-topic to another. */
168	async function handleReassignClaims(
169	  db: ReturnType<typeof getDirectDb>,
170	  payload: ProposalPayload,
171	): Promise<HandlerResult> {
172	  const fromSubTopicId = payload.fromSubTopicId as string | undefined;
173	  const toSubTopicId = payload.toSubTopicId as string | undefined;
174	  const claimIds = payload.claimIds as string[] | undefined;
175	
176	  if (!fromSubTopicId || !toSubTopicId) {
177	    return { applied: false, reason: 'payload missing fromSubTopicId or toSubTopicId' };
178	  }
179	
180	  const targetExists = await db
181	    .select({ id: knowledgeSubTopics.id })
182	    .from(knowledgeSubTopics)
183	    .where(eq(knowledgeSubTopics.id, toSubTopicId))
184	    .limit(1);
185	  if (!targetExists.length) {
186	    return { applied: false, reason: `target sub-topic ${toSubTopicId} not found` };
187	  }
188	
189	  const whereClause =
190	    claimIds && claimIds.length > 0
191	      ? and(eq(claimSubTopics.subTopicId, fromSubTopicId), inArray(claimSubTopics.claimId, claimIds))
192	      : eq(claimSubTopics.subTopicId, fromSubTopicId);
193	
194	  // Re-point existing rows; skip claims already in the target.
195	  const alreadyInTarget = await db
196	    .select({ claimId: claimSubTopics.claimId })
197	    .from(claimSubTopics)
198	    .where(eq(claimSubTopics.subTopicId, toSubTopicId));
199	  const skipIds = alreadyInTarget.map((r) => r.claimId);
200	
201	  const finalWhere =
202	    skipIds.length > 0
203	      ? and(whereClause, notInArray(claimSubTopics.claimId, skipIds))
204	      : whereClause;
205	
206	  const updated = await db
207	    .update(claimSubTopics)
208	    .set({ subTopicId: toSubTopicId })
209	    .where(finalWhere)
210	    .returning({ claimId: claimSubTopics.claimId });
211	
212	  return {
213	    applied: true,
214	    afterState: { fromSubTopicId, toSubTopicId, reassignedCount: updated.length },
215	  };
216	}
217	
218	/** merge_sub_topics: move all members of source into target, then retire source. */
219	async function handleMergeSubTopics(
220	  db: ReturnType<typeof getDirectDb>,
221	  payload: ProposalPayload,
222	): Promise<HandlerResult> {
223	  const sourceSubTopicId = payload.sourceSubTopicId as string | undefined;
224	  const targetSubTopicId = payload.targetSubTopicId as string | undefined;
225	
226	  if (!sourceSubTopicId || !targetSubTopicId) {
227	    return { applied: false, reason: 'payload missing sourceSubTopicId or targetSubTopicId' };
228	  }
229	  if (sourceSubTopicId === targetSubTopicId) {
230	    return { applied: false, reason: 'source and target sub-topic IDs are the same' };
231	  }
232	
233	  // Move claims not already in target.
234	  const alreadyInTarget = await db
235	    .select({ claimId: claimSubTopics.claimId })
236	    .from(claimSubTopics)
237	    .where(eq(claimSubTopics.subTopicId, targetSubTopicId));
238	  const skipIds = alreadyInTarget.map((r) => r.claimId);
239	
240	  const moveWhere =
241	    skipIds.length > 0
242	      ? and(eq(claimSubTopics.subTopicId, sourceSubTopicId), notInArray(claimSubTopics.claimId, skipIds))
243	      : eq(claimSubTopics.subTopicId, sourceSubTopicId);
244	
245	  const moved = await db
246	    .update(claimSubTopics)
247	    .set({ subTopicId: targetSubTopicId })
248	    .where(moveWhere)
249	    .returning({ claimId: claimSubTopics.claimId });
250	
251	  // Delete any leftover rows pointing at source (duplicates that were in target).
252	  await db
253	    .delete(claimSubTopics)
254	    .where(eq(claimSubTopics.subTopicId, sourceSubTopicId));
255	
256	  // Retire source sub-topic.
257	  await db
258	    .update(knowledgeSubTopics)
259	    .set({ reviewStatus: 'retired' })
260	    .where(eq(knowledgeSubTopics.id, sourceSubTopicId));
261	
262	  return {
263	    applied: true,
264	    afterState: {
265	      sourceSubTopicId,
266	      targetSubTopicId,
267	      movedCount: moved.length,
268	      sourceStatus: 'retired',
269	    },
270	  };
271	}
272	
273	/** retire_sub_topic: mark retired, detach all claim_sub_topics rows. */
274	async function handleRetireSubTopic(
275	  db: ReturnType<typeof getDirectDb>,
276	  payload: ProposalPayload,
277	): Promise<HandlerResult> {
278	  const subTopicId = payload.subTopicId as string | undefined;
279	  if (!subTopicId) {
280	    return { applied: false, reason: 'payload missing subTopicId' };
281	  }
282	
283	  const detached = await db
284	    .delete(claimSubTopics)
285	    .where(eq(claimSubTopics.subTopicId, subTopicId))
286	    .returning({ claimId: claimSubTopics.claimId });
287	
288	  await db
289	    .update(knowledgeSubTopics)
290	    .set({ reviewStatus: 'retired' })
291	    .where(eq(knowledgeSubTopics.id, subTopicId));
292	
293	  return {
294	    applied: true,
295	    afterState: { subTopicId, detachedClaimsCount: detached.length, status: 'retired' },
296	  };
297	}
