1	// R10.5 — Taxonomy re-evaluation worker.
2	//
3	// Per docs/oracle/05-ai-retrofit-phase-packet.md Phase R10.5 task 1+2.
4	//
5	// Goal: periodically scan promoted claims, detect that the current taxonomy
6	// no longer fits the data, and WRITE PROPOSALS to `taxonomy_proposals` for
7	// admin review. The worker MUST NEVER auto-mutate the taxonomy — that
8	// invariant is the whole reason this dashboard + queue exists.
9	//
10	// What this worker does (R10.5 full implementation):
11	//   1. Per-domain density clustering on stored claim embeddings (k-means,
12	//      cosine distance, k = min(8, max(2, round(sqrt(N/4)))), 30 iterations).
13	//   2. Cluster naming via a cheap synthesis call (Gemini Flash extraction
14	//      route). Top-5 claim summaries per cluster are sent as evidence.
15	//   3. Overlap analysis: clusters whose centroid has cosine similarity >=
16	//      NOVELTY_COSINE_THRESHOLD to any existing knowledge_sub_topics.centroid
17	//      row for the same domain are skipped (already represented).
18	//   4. Proposal writing to `taxonomy_proposals` only (no other tables).
19	//   5. Proposal payloads match the TaxonomyProposalPayload contract in
20	//      docs/oracle/07-knowledge-segmentation.md.
21	//
22	// Domains below DEFAULT_ACTIVATION_THRESHOLD (30 approved claims with
23	// non-null embeddings) are skipped — clustering centroids need enough
24	// mass to be meaningful. See file header comment for rationale on 30 vs
25	// the spec's conservative 100.
26	//
27	// The admin dashboard at `/admin/taxonomy/proposals` is the consumer.
28	
29	import { schedules, task } from '@trigger.dev/sdk/v3';
30	import { and, desc, eq, isNotNull, sql } from 'drizzle-orm';
31	import { z } from 'zod';
32	import { getDirectDb } from '@oracle/db/client';
33	import {
34	  claims,
35	  claimTopDomains,
36	  jobRuns,
37	  knowledgeSubTopics,
38	  knowledgeTopDomains,
39	  modelRuns,
40	  taxonomyProposals,
41	} from '@oracle/db';
42	import {
43	  OracleAIClient,
44	  buildStandardAdapters,
45	  makeBlock,
46	} from '@oracle/ai';
