48	// ─────────────────────────────────────────────────────────────────────────
49	// Constants
50	// ─────────────────────────────────────────────────────────────────────────
51	
52	const DEFAULT_ACTIVATION_THRESHOLD = 30;
53	/** Minimum members a cluster must have to be considered for a proposal. */
54	const MIN_CLUSTER_SIZE = 3;
55	/** Cosine similarity above which a new cluster is considered already represented by an existing sub-topic. */
56	const NOVELTY_COSINE_THRESHOLD = 0.88;
57	/** Max clusters per domain — prevents proposal flooding on large domains. */
58	const MAX_K = 8;
59	/** LLM prompt version for observability. */
60	const CLUSTER_NAMING_PROMPT_VERSION = '1.0.0';
61	/** Extraction route used for cluster naming. */
62	const CLUSTER_NAMING_ROUTE_ID = 'vertex_gemini_2_5_flash_extraction_primary';
63	
64	// ─────────────────────────────────────────────────────────────────────────
65	// K-means helpers (pure TS, no new deps)
66	// ─────────────────────────────────────────────────────────────────────────
67	
68	function cosineSimilarity(a: number[], b: number[]): number {
69	  let dot = 0, normA = 0, normB = 0;
70	  for (let i = 0; i < a.length; i++) {
71	    dot += (a[i] ?? 0) * (b[i] ?? 0);
72	    normA += (a[i] ?? 0) ** 2;
73	    normB += (b[i] ?? 0) ** 2;
74	  }
75	  const denom = Math.sqrt(normA) * Math.sqrt(normB);
76	  return denom === 0 ? 0 : dot / denom;
77	}
78	
79	function computeCentroid(vectors: number[][]): number[] {
80	  if (vectors.length === 0) return [];
81	  const dim = vectors[0]!.length;
82	  const centroid = new Array<number>(dim).fill(0);
83	  for (const v of vectors) {
84	    for (let i = 0; i < dim; i++) centroid[i]! += (v[i] ?? 0) / vectors.length;
85	  }
86	  return centroid;
87	}
88	
89	function kMeans(
90	  vectors: number[][],
91	  k: number,
92	  maxIter = 30,
93	): Array<{ centroid: number[]; memberIndices: number[] }> {
94	  if (vectors.length === 0 || k <= 0) return [];
95	  k = Math.min(k, vectors.length);
96	
97	  // k-means++ initialisation
98	  const centroids: number[][] = [vectors[Math.floor(Math.random() * vectors.length)]!];
99	  while (centroids.length < k) {
100	    const dists = vectors.map((v) => {
101	      const bestSim = centroids.reduce((m, c) => Math.max(m, cosineSimilarity(v, c)), -Infinity);
102	      return Math.max(0, 1 - bestSim);
103	    });
104	    const totalDist = dists.reduce((s, d) => s + d, 0);
105	    let rand = Math.random() * totalDist;
106	    let chosen = 0;
107	    for (let i = 0; i < dists.length; i++) {
108	      rand -= dists[i]!;
109	      if (rand <= 0) { chosen = i; break; }
110	    }
111	    centroids.push(vectors[chosen]!);
112	  }
113	
114	  let assignments = new Array<number>(vectors.length).fill(0);
115	
116	  for (let iter = 0; iter < maxIter; iter++) {
117	    const newAssignments = vectors.map((v) => {
118	      let bestIdx = 0, bestSim = -Infinity;
119	      for (let c = 0; c < centroids.length; c++) {
120	        const sim = cosineSimilarity(v, centroids[c]!);
121	        if (sim > bestSim) { bestSim = sim; bestIdx = c; }
122	      }
123	      return bestIdx;
124	    });
125	
126	    for (let c = 0; c < k; c++) {
127	      const members = vectors.filter((_, i) => newAssignments[i] === c);
128	      if (members.length > 0) centroids[c] = computeCentroid(members);
129	    }
130	
131	    if (newAssignments.every((a, i) => a === assignments[i])) break;
132	    assignments = newAssignments;
133	  }
134	
135	  return Array.from({ length: k }, (_, c) => ({
136	    centroid: centroids[c]!,
137	    memberIndices: assignments.reduce<number[]>((acc, a, i) => { if (a === c) acc.push(i); return acc; }, []),
138	  }));
139	}
