141	// ─────────────────────────────────────────────────────────────────────────
142	// OracleAIClient factory
143	// ─────────────────────────────────────────────────────────────────────────
144	
145	function buildOracleClient(): OracleAIClient {
146	  return new OracleAIClient({
147	    adapters: buildStandardAdapters(),
148	    fallbackOnError: true,
149	  });
150	}
151	
152	// ─────────────────────────────────────────────────────────────────────────
153	// Cluster naming via cheap LLM call
154	// ─────────────────────────────────────────────────────────────────────────
155	
156	type ClusterName = { name: string; purpose: string };
157	
158	async function nameCluster(
159	  client: OracleAIClient,
160	  domainId: string,
161	  claimSummaries: string[],
162	): Promise<ClusterName> {
163	  const topSummaries = claimSummaries.slice(0, 5);
164	  const listText = topSummaries.map((s, i) => `${i + 1}. ${s}`).join('\n');
165	
166	  const result = await client.runText({
167	    taskType: 'admin_explanation',
168	    routeId: CLUSTER_NAMING_ROUTE_ID,
169	    promptVersion: CLUSTER_NAMING_PROMPT_VERSION,
170	    blocks: [
171	      makeBlock({
172	        id: 'cluster-naming-system',
173	        label: 'Cluster naming system prompt',
174	        kind: 'stable_system',
175	        content: `You are a taxonomy assistant for a product licensing and manufacturing company.
176	Given a set of claim summaries that cluster together within a knowledge domain, your job is to assign a short descriptive sub-topic name and one-sentence purpose.
177	
178	Rules:
179	- Name: 2–6 words, title case, no punctuation at the end.
180	- Purpose: one sentence, plain English, describes what claims in this sub-topic have in common.
181	- Return ONLY valid JSON: {"name": "...", "purpose": "..."}`,
182	        reasonIncluded: 'cluster naming stable system',
183	      }),
184	      makeBlock({
185	        id: 'cluster-naming-input',
186	        label: 'Claim summaries for this cluster',
187	        kind: 'dynamic_input',
188	        content: `Domain: ${domainId}\n\nClaim summaries:\n${listText}\n\nReturn JSON only.`,
189	        reasonIncluded: `${topSummaries.length} representative claims`,
190	      }),
191	    ],
192	  });
193	
194	  try {
195	    const jsonMatch = /\{[\s\S]*\}/.exec(result.text);
196	    if (jsonMatch) {
197	      const parsed = JSON.parse(jsonMatch[0]) as unknown;
198	      if (
199	        parsed &&
200	        typeof parsed === 'object' &&
201	        'name' in parsed &&
202	        'purpose' in parsed &&
203	        typeof (parsed as Record<string, unknown>).name === 'string' &&
204	        typeof (parsed as Record<string, unknown>).purpose === 'string'
205	      ) {
206	        return {
207	          name: String((parsed as Record<string, unknown>).name),
208	          purpose: String((parsed as Record<string, unknown>).purpose),
209	        };
210	      }
211	    }
212	  } catch {
213	    // fall through to fallback
214	  }
215	
216	  return {
217	    name: `${domainId.replace(/_/g, ' ')} cluster`,
218	    purpose: `A group of related claims within the ${domainId} domain discovered by automated clustering.`,
219	  };
220	}
221	
222	// ─────────────────────────────────────────────────────────────────────────
223	// Per-domain clustering
224	// ─────────────────────────────────────────────────────────────────────────
225	
226	type ClaimRow = { id: string; summary: string; embedding: number[] };
227	
228	async function processReadyDomain(
229	  db: ReturnType<typeof getDirectDb>,
230	  client: OracleAIClient,
231	  domainId: string,
232	): Promise<number> {
233	  // Load approved claims with non-null embeddings for this domain.
234	  const rows = await db
235	    .select({
236	      id: claims.id,
237	      summary: claims.summary,
238	      embedding: claims.embedding,
239	    })
240	    .from(claims)
241	    .innerJoin(claimTopDomains, eq(claimTopDomains.claimId, claims.id))
242	    .where(
243	      and(
244	        eq(claimTopDomains.topDomainId, domainId),
245	        eq(claims.status, 'approved'),
246	        isNotNull(claims.embedding),
247	      ),
248	    )
249	    .orderBy(desc(claims.impactScore))
250	    .limit(500);
251	
252	  const claimRows = rows.filter((r): r is ClaimRow => r.embedding !== null && r.embedding.length > 0);
253	  if (claimRows.length < MIN_CLUSTER_SIZE) return 0;
254	
255	  const k = Math.min(MAX_K, Math.max(2, Math.round(Math.sqrt(claimRows.length / 4))));
256	  const vectors = claimRows.map((r) => r.embedding);
257	  const clusters = kMeans(vectors, k);
258	
259	  // Load existing approved/pending sub-topic centroids for this domain to
260	  // detect novelty. Skip clusters that are already represented.
261	  const existingSubTopics = await db
262	    .select({ centroid: knowledgeSubTopics.centroid })
263	    .from(knowledgeSubTopics)
264	    .where(eq(knowledgeSubTopics.topDomainId, domainId));
265	
266	  const existingCentroids = existingSubTopics
267	    .map((st) => st.centroid)
268	    .filter((c): c is number[] => c !== null && c.length > 0);
269	
270	  let proposalsWritten = 0;
271	
272	  for (const cluster of clusters) {
273	    if (cluster.memberIndices.length < MIN_CLUSTER_SIZE) continue;
274	
275	    // Novelty check: skip if too similar to an existing sub-topic.
276	    const maxExistingSim = existingCentroids.reduce(
277	      (max, existing) => Math.max(max, cosineSimilarity(cluster.centroid, existing)),
278	      -Infinity,
279	    );
280	    if (maxExistingSim >= NOVELTY_COSINE_THRESHOLD) continue;
281	
282	    // Build evidence list (top members by original claim order, already
283	    // sorted desc by impact_score above).
284	    const memberClaims = cluster.memberIndices
285	      .sort((a, b) => a - b)
286	      .slice(0, 5)
287	      .map((i) => claimRows[i]!)
288	      .filter(Boolean);
289	
290	    const summaries = memberClaims.map((c) => c.summary);
291	    let clusterName: ClusterName;
292	    let modelRunId: string | null = null;
293	    const callStart = Date.now();
294	
295	    try {
296	      clusterName = await nameCluster(client, domainId, summaries);
297	      const latencyMs = Date.now() - callStart;
298	
299	      const [mr] = await db
300	        .insert(modelRuns)
301	        .values({
302	          taskType: 'taxonomy-cluster-naming',
303	          model: 'gemini-2.5-flash',
304	          provider: 'vertex',
305	          promptVersion: CLUSTER_NAMING_PROMPT_VERSION,
306	          latencyMs,
307	          success: true,
308	        })
309	        .returning({ id: modelRuns.id });
310	      modelRunId = mr?.id ?? null;
311	    } catch {
312	      // Naming failed — use a generic fallback so the cluster isn't lost.
313	      const latencyMs = Date.now() - callStart;
314	      clusterName = {
315	        name: `${domainId.replace(/_/g, ' ')} cluster`,
316	        purpose: `A group of ${cluster.memberIndices.length} claims within ${domainId} discovered by automated clustering.`,
317	      };
318	      await db.insert(modelRuns).values({
319	        taskType: 'taxonomy-cluster-naming',
320	        model: 'gemini-2.5-flash',
321	        provider: 'vertex',
322	        promptVersion: CLUSTER_NAMING_PROMPT_VERSION,
323	        latencyMs,
324	        success: false,
325	        error: 'cluster naming LLM call failed',
326	      });
327	    }
328	
329	    // Build proposal payload per TaxonomyProposalPayload contract in
330	    // docs/oracle/07-knowledge-segmentation.md.
331	    // Extra fields (topDomainId, clusterCentroid, representativeClaimIds) are
332	    // not part of the base contract but are consumed by the
333	    // taxonomy-reclassification worker to create the sub-topic row.
334	    const payload = {
335	      proposedName: clusterName.name,
336	      oneSentencePurpose: clusterName.purpose,
337	      proposalReason: `Automated k-means clustering (k=${k}) on ${claimRows.length} approved claim embeddings in domain "${domainId}" identified a cluster of ${cluster.memberIndices.length} claims with no sufficiently similar existing sub-topic (max existing centroid similarity: ${maxExistingSim === -Infinity ? 'none' : maxExistingSim.toFixed(3)}).`,
338	      topDomainId: domainId,
339	      clusterCentroid: cluster.centroid,
340	      representativeEvidence: memberClaims.map((c) => ({
341	        sourceType: 'claim' as const,
342	        sourceId: c.id,
343	        shortSnippet: c.summary.slice(0, 200),
344	        whyRepresentative: 'Selected as top member of this cluster by claim order (impact score desc)',
345	      })),
346	      representativeClaimIds: memberClaims.map((c) => c.id),
347	      commonEntities: [],
348	      affectedCounts: { claims: cluster.memberIndices.length },
349	      suggestedRetrievalExclusions: [],
350	      recommendedAction: 'approve' as const,
351	      recommendedActionReason: `Cluster has ${cluster.memberIndices.length} members and appears meaningfully distinct from existing sub-topics.`,
352	      confidence: Math.min(0.95, 0.5 + cluster.memberIndices.length / 50),
353	    };
354	
355	    await db.insert(taxonomyProposals).values({
356	      proposalType: 'create_sub_topic',
357	      payload,
358	      proposedByModelRunId: modelRunId ?? undefined,
359	      status: 'pending',
360	    });
361	
362	    proposalsWritten++;
363	  }
364	
365	  return proposalsWritten;
366	}
367	
368	// ─────────────────────────────────────────────────────────────────────────
369	// Main logic
370	// ─────────────────────────────────────────────────────────────────────────
371	
372	const ManualTriggerPayload = z.object({
373	  topDomainId: z.string().optional(),
374	  activationThreshold: z.number().int().positive().optional(),
375	});
376	
377	type DomainCountRow = {
378	  top_domain_id: string;
379	  claim_count: number;
380	};
381	
382	async function runReevaluation(args: {
383	  triggerRunId: string;
384	  trigger: 'scheduled' | 'manual';
385	  topDomainFilter?: string;
386	  activationThreshold: number;
387	}): Promise<{
388	  ok: true;
389	  trigger: 'scheduled' | 'manual';
390	  totalClaims: number;
391	  domainsScanned: number;
392	  domainsReady: number;
393	  domainsBelowThreshold: number;
394	  proposalsWritten: number;
395	  note: string;
396	}> {
397	  const db = getDirectDb();
398	  const client = buildOracleClient();
399	
400	  const [jobRun] = await db
401	    .insert(jobRuns)
402	    .values({
403	      triggerRunId: args.triggerRunId,
404	      jobType: 'taxonomy-reevaluation',
405	      status: 'running',
406	      startedAt: new Date(),
407	      inputJson: {
408	        trigger: args.trigger,
409	        topDomainFilter: args.topDomainFilter ?? null,
410	        activationThreshold: args.activationThreshold,
411	      },
412	    })
413	    .returning({ id: jobRuns.id });
414	  if (!jobRun) throw new Error('[taxonomy-reevaluation] failed to insert job_runs row');
415	
416	  try {
417	    const domainFilter = args.topDomainFilter ? sql`AND d.id = ${args.topDomainFilter}` : sql``;
418	    const result = await db.execute(sql`
419	      SELECT d.id AS top_domain_id,
420	             COALESCE((
421	               SELECT COUNT(DISTINCT ctd.claim_id)
422	               FROM claim_top_domains ctd
423	               JOIN claims c ON c.id = ctd.claim_id
424	               WHERE ctd.top_domain_id = d.id
425	                 AND c.status = 'approved'
426	                 AND c.embedding IS NOT NULL
427	             ), 0) AS claim_count
428	      FROM knowledge_top_domains d
429	      WHERE d.is_active = true
430	      ${domainFilter}
431	      ORDER BY d.display_order
432	    `);
433	    const rows = [...result] as unknown as DomainCountRow[];
434	
435	    const totalClaims = rows.reduce((sum, r) => sum + Number(r.claim_count), 0);
436	    const readyRows = rows.filter((r) => Number(r.claim_count) >= args.activationThreshold);
437	    const domainsReady = readyRows.length;
438	    const domainsBelowThreshold = rows.length - domainsReady;
439	
440	    let proposalsWritten = 0;
441	    const perDomainResults: Record<string, { claimsWithEmbeddings: number; proposals: number }> = {};
442	
443	    for (const row of readyRows) {
444	      const written = await processReadyDomain(db, client, row.top_domain_id);
445	      proposalsWritten += written;
446	      perDomainResults[row.top_domain_id] = {
447	        claimsWithEmbeddings: Number(row.claim_count),
448	        proposals: written,
449	      };
450	    }
451	
452	    const note =
453	      domainsReady === 0
454	        ? `No active domain has reached the ${args.activationThreshold}-claim activation threshold (counting only approved claims with embeddings). Sub-topic clustering remains disabled.`
455	        : `Clustered ${domainsReady} of ${rows.length} active domains. Wrote ${proposalsWritten} create_sub_topic proposal(s) for admin review.`;
456	
457	    const output = {
458	      ok: true as const,
459	      trigger: args.trigger,
460	      totalClaims,
461	      domainsScanned: rows.length,
462	      domainsReady,
463	      domainsBelowThreshold,
464	      proposalsWritten,
465	      note,
466	    };
467	
468	    await db
469	      .update(jobRuns)
470	      .set({
471	        status: 'complete',
472	        finishedAt: new Date(),
473	        outputJson: { ...output, perDomainCounts: rows, perDomainResults },
474	      })
475	      .where(sql`id = ${jobRun.id}`);
476	
477	    return output;
478	  } catch (err) {
479	    await db
480	      .update(jobRuns)
481	      .set({
482	        status: 'failed',
483	        finishedAt: new Date(),
484	        error: err instanceof Error ? err.message : String(err),
485	      })
486	      .where(sql`id = ${jobRun.id}`);
487	    throw err;
488	  }
489	}
