492	// Tasks
493	// ─────────────────────────────────────────────────────────────────────────
494	
495	// Scheduled cadence: weekly, every Monday at 7 AM (one hour after the
496	// brain-synthesis-scheduled task at 6 AM Monday).
497	export const taxonomyReevaluationScheduledTask = schedules.task({
498	  id: 'taxonomy-reevaluation',
499	  cron: '0 7 * * 1',
500	  maxDuration: 60 * 10,
501	  run: async (_payload, { ctx }) => {
