115	export const teamsTranscriptIngestionTask = task({
116	  id: 'teams-transcript-ingestion',
117	  maxDuration: 60 * 5,
118	  run: async (payload: IngestionPayload, { ctx }) => {
119	    const db = getDirectDb();
120	    const [jobRun] = await db
121	      .insert(jobRuns)
122	      .values({
123	        triggerRunId: ctx.run.id,
124	        jobType: 'teams-transcript-ingestion',
125	        status: 'running',
126	        startedAt: new Date(),
127	        inputJson: payload,
128	      })
129	      .returning({ id: jobRuns.id });
130	    if (!jobRun) throw new Error('[teams-transcript-ingestion] failed to insert job_runs row');
131	
132	    try {
133	      const transcriptId = deriveTranscriptId(payload);
134	
135	      // Idempotency: bail if we've already ingested this transcript.
136	      const already = await db
137	        .select({ id: messages.id })
138	        .from(messages)
139	        .where(sql`${messages.clientMessageId} like ${`teams:${transcriptId}:%`}`)
140	        .limit(1);
141	      if (already.length > 0) {
142	        const out = { skipped: true, reason: 'already ingested', transcriptId };
143	        await db
144	          .update(jobRuns)
145	          .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
146	          .where(eq(jobRuns.id, jobRun.id));
147	        return { ok: true, ...out };
148	      }
149	
150	      const vtt = await fetchTranscriptVtt(
151	        payload.transcriptContentUrl ?? null,
152	        payload.resourcePath ?? null,
153	      );
154	      const cues = mergeBySpeaker(parseVtt(vtt));
155	
156	      if (cues.length === 0) {
157	        const out = { transcriptId, messages: 0, reason: 'empty transcript' };
158	        await db
159	          .update(jobRuns)
160	          .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
161	          .where(eq(jobRuns.id, jobRun.id));
162	        return { ok: true, ...out };
163	      }
164	
165	      // Speaker → employee resolution.
166	      // Primary path: VTT display name -> M365 directory email -> employee by
167	      // email (employees.email or any employee_identities.email). This mirrors
168	      // the auth linker's email-based identity model and is robust to display
169	      // names that don't equal employees.name. Fallback: display-name match.
170	      const emps = await db
171	        .select({ id: employees.id, name: employees.name, email: employees.email })
172	        .from(employees);
173	      const idents = await db
174	        .select({ employeeId: employeeIdentities.employeeId, email: employeeIdentities.email })
175	        .from(employeeIdentities);
176	      const byName = new Map<string, string>();
177	      const byEmail = new Map<string, string>();
178	      for (const e of emps) {
179	        if (e.name) byName.set(e.name.trim().toLowerCase(), e.id);
180	        if (e.email) byEmail.set(e.email.trim().toLowerCase(), e.id);
181	      }
182	      for (const i of idents) {
183	        const key = i.email?.trim().toLowerCase();
184	        if (key && !byEmail.has(key)) byEmail.set(key, i.employeeId);
185	      }
186	      let displayNameToEmail = new Map<string, string>();
187	      try {
188	        displayNameToEmail = await listDisplayNameToEmail();
189	      } catch (err) {
190	        console.warn('[teams-transcript-ingestion] directory lookup failed; using name match only', err);
191	      }
192	      const resolveExisting = (speaker: string): string | null => {
193	        const key = speaker.trim().toLowerCase();
194	        const email = displayNameToEmail.get(key);
195	        if (email) {
196	          const viaEmail = byEmail.get(email);
197	          if (viaEmail) return viaEmail;
198	        }
199	        return byName.get(key) ?? null;
200	      };
201	
202	      // Resolve each distinct speaker once. Bootstrap-create an employee for a
203	      // speaker who maps to an @popcre.com directory user but isn't onboarded
204	      // yet — mirrors the auth linker's email-based bootstrap. Scoped to
205	      // @popcre.com so external/guest participants stay unattributed (null).
206	      const resolvedBySpeaker = new Map<string, string | null>();
207	      const bootstrapped: string[] = [];
208	      const distinctSpeakers = [
209	        ...new Set(cues.map((c) => c.speaker).filter((s): s is string => Boolean(s))),
210	      ];
211	      for (const speaker of distinctSpeakers) {
212	        let empId = resolveExisting(speaker);
213	        if (!empId) {
214	          const email = displayNameToEmail.get(speaker.trim().toLowerCase());
215	          if (email && email.endsWith('@popcre.com')) {
216	            const [created] = await db
217	              .insert(employees)
218	              .values({ name: speaker.trim(), email, role: 'Employee' })
219	              .onConflictDoNothing({ target: employees.email })
220	              .returning({ id: employees.id });
221	            if (created) {
222	              empId = created.id;
223	              bootstrapped.push(email);
224	            } else {
225	              const [ex] = await db
226	                .select({ id: employees.id })
227	                .from(employees)
228	                .where(eq(employees.email, email))
229	                .limit(1);
230	              empId = ex?.id ?? null;
231	            }
232	            if (empId) byEmail.set(email, empId);
233	          }
234	        }
235	        resolvedBySpeaker.set(speaker, empId);
236	      }
237	
238	      const base = Date.now(); // TODO: anchor to real meeting start when available
239	      const [channel] = await db
240	        .insert(channels)
241	        .values({
242	          name: `Teams call ${new Date(base).toISOString().slice(0, 16).replace('T', ' ')} UTC`,
243	          isGroupChat: true,
244	          status: 'active',
245	        })
246	        .returning({ id: channels.id });
247	      if (!channel) throw new Error('failed to create channel for transcript');
248	
249	      // Persist the raw VTT so the entire pipeline (parsing → messages →
250	      // extraction → synthesis) stays re-runnable from true source even after
251	      // Microsoft expires the transcript. The `messages` rows are already a
252	      // lossy transform (merged turns, resolved speakers); this is the raw.
253	      await db.execute(sql`
254	        insert into raw_transcripts (channel_id, call_id, transcript_id, vtt)
255	        values (${channel.id}::uuid, ${payload.callId ?? null}, ${transcriptId}, ${vtt})
256	        on conflict (transcript_id) do nothing
257	      `);
258	
259	      const participantIds = new Set<string>();
260	      const rows = cues.map((c, i) => {
261	        const employeeId = c.speaker ? (resolvedBySpeaker.get(c.speaker) ?? null) : null;
262	        if (employeeId) participantIds.add(employeeId);
263	        return {
264	          channelId: channel.id,
265	          employeeId,
266	          role: 'user' as const,
267	          content: c.text,
268	          clientMessageId: `teams:${transcriptId}:${i}`,
269	          extractionStatus: 'pending' as const,
270	          createdAt: new Date(base + c.offsetMs),
271	          metadataJson: {
272	            source: 'teams_transcript',
273	            transcriptId,
274	            meetingId: payload.meetingId ?? null,
275	            callId: payload.callId ?? null,
276	            speaker: c.speaker,
277	            offsetMs: c.offsetMs,
278	            resolvedEmployeeId: employeeId,
279	          },
280	        };
281	      });
282	
283	      await db.insert(messages).values(rows);
284	      for (const employeeId of participantIds) {
285	        await db
286	          .insert(channelParticipants)
287	          .values({ channelId: channel.id, employeeId })
288	          .onConflictDoNothing();
289	      }
290	
291	      const out = {
292	        transcriptId,
293	        channelId: channel.id,
294	        messages: rows.length,
295	        speakersResolved: participantIds.size,
296	        speakersTotal: new Set(cues.map((c) => c.speaker)).size,
297	        bootstrapped: bootstrapped.length,
298	      };
299	      await db
300	        .update(jobRuns)
301	        .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
302	        .where(eq(jobRuns.id, jobRun.id));
303	      return { ok: true, ...out };
304	    } catch (err) {
305	      const errMsg = err instanceof Error ? err.message : String(err);
306	      await db
307	        .update(jobRuns)
308	        .set({ status: 'failed', finishedAt: new Date(), error: errMsg })
309	        .where(eq(jobRuns.id, jobRun.id));
310	      throw err;
311	    }
312	  },
313	});
